class InventoryItem:
    def __init__(self, n, qty, rl):
        self.name = n
        self.stock = qty
        self.reorder_level = rl
        if self.reorder_level < 0:
            raise ValueError("Reorder level cannot be negative")
        if self.reorder_level > self.stock:
            raise ValueError("Reorder level cannot exceed initial stock")

    def add_stock(self, amount):
        if amount <= 0:
            return False
        self.stock += amount
        return True

    def remove_stock(self, amount):
        if amount <= 0 or amount > self.stock:
            return False
        self.stock -= amount
        return True

    def needs_reorder(self):
        return self.stock <= self.reorder_level

    def restock(self, amt):
        if amt <= 0:
            return False
        if self.remove_stock(1):
            self.add_stock(amt + 1)
            return True
        return False

    def get_status(self):
        return {
            "name": self.name,
            "stock": self.stock,
            "reorder_level": self.reorder_level,
            "needs_reorder": self.needs_reorder()
        }

item1 = InventoryItem("Laptop", 10, 3)
assert item1.remove_stock(5) is True
assert item1.remove_stock(10) is False
assert item1.add_stock(5) is True
assert item1.needs_reorder() is False
item1.remove_stock(8)
assert item1.needs_reorder() is True
assert item1.restock(5) is True
assert item1.stock == 2

def calculate_discounted_price(quantity, unit_price):
    total = quantity * unit_price
    if quantity >= 10:
        total *= 0.9
    elif quantity >= 20:
        total *= 0.8
    elif quantity >= 30:
        total *= 0.7
    return round(total, 2)

def main():
    assert calculate_discounted_price(5, 10) == 50
    assert calculate_discounted_price(10, 10) == 90.0
    assert calculate_discounted_price(15, 10) == 135.0
    assert calculate_discounted_price(20, 10) == 160.0
    assert calculate_discounted_price(25, 10) == 200.0
    assert calculate_discounted_price(30, 10) == 210.0
    assert calculate_discounted_price(3.5, 10) == 31.5

main()

def parse_range_string(s):
    if not s or '=' not in s or ',' not in s:
        raise ValueError("invalid format: must contain 'start=' and 'end=' separated by comma")
    try:
        parts = s.split(',')
        start_part = parts[0].strip()
        end_part = parts[1].strip()
        if not start_part.startswith('start=') or not end_part.startswith('end='):
            raise ValueError("missing 'start=' or 'end=' prefix")
        start_val_str = start_part.split('=')[1]
        end_val_str = end_part.split('=')[1]
        if not start_val_str.isdigit() and not (start_val_str[0] == '-' and start_val_str[1:].isdigit()):
            raise ValueError("start value is not a valid integer")
        if not end_val_str.isdigit() and not (end_val_str[0] == '-' and end_val_str[1:].isdigit()):
            raise ValueError("end value is not a valid integer")
        start_val = int(start_val_str)
        end_val = int(end_val_str)
        if start_val > end_val:
            raise ValueError("start value must be less than or equal to end value")
        return list(range(start_val, end_val))  
    except IndexError:
        raise ValueError("malformed string: missing start or end part")
    except Exception as e:
        if isinstance(e, ValueError):
            raise e
        else:
            raise ValueError("parsing failed due to invalid input format")

assert parse_range_string('start=1, end=3') == [1, 2, 3]
assert parse_range_string('start=-1, end=1') == [-1, 0, 1]
assert parse_range_string('start=5, end=5') == [5]
