    assert False
except ValueError:
    assert True
try:
    parse_range_string('invalid input')
    assert False
except ValueError:
    assert True

def validate_format_string(fmt_str, val_dict):
    try:
        fmt_str.format(**val_dict)
    except KeyError as e:
        missing_key = str(e).strip("'")
        raise KeyError(f'Missing key: {missing_key}') from None
    except (TypeError, ValueError) as e:
        if "unknown format code" in str(e) or "format requires a mapping" in str(e):
            raise TypeError('Invalid type for formatting') from None
        elif "unsupported format string" in str(e):
            raise TypeError('Invalid type for formatting') from None
        else:
            raise
    except Exception as e:
        raise TypeError('Invalid type for formatting')


def check_format(s, d):
    try:
        validate_format_string(s, d)
        return True
    except:
        return False


assert check_format("Hello {name}", {"name": "Alice"}) == True
assert check_format("Age: {age:d}", {"age": "notint"}) == False
try:
    validate_format_string("Missing {key}", {})
except KeyError as e:
    assert str(e) == "'Missing key: key'"
try:
    validate_format_string("{bad_format:z}", {"bad_format": 5})
except ValueError:
    assert True
try:
    validate_format_string("Age: {age:d}", {"age": "notint"})
except TypeError as e:
    assert str(e) == 'Invalid type for formatting'

def generate_substrings(s):
    def _gen_substrings(prefix, rest):
        if prefix:
            yield prefix
        for i in range(len(rest)):
            new_prefix = prefix + rest[i]
            yield from _gen_substrings(new_prefix, rest[i:])

    def _sort_and_yield():
        substrings = list(_gen_substrings("", s))
        substrings.sort()
        for sub in substrings:
            yield sub

    yield from _sort_and_yield()


def get_all_subs(t):
    return list(generate_substrings(t))


