class Book:
    def __init__(self, title, author, isbn):
        self.title = title
        self.author = author
        if isinstance(isbn, str) and len(isbn) > 0:
            self.isbn = isbn
        else:
            raise ValueError("ISBN must be a non-empty string")
        self.avail = True

    def mark_borrowed(self):
        if self.avail:
            self.avail = False
            return True
        return False

    def mark_returned(self):
        if self.avail:
            self.avail = True
            return True
        return False

    def get_info(self):
        status = "Available" if self.avail else "Borrowed"
        info = f"Title: {self.title}, Author: {self.author}, ISBN: {self.isbn}, Status: {status}"
        return info

    def is_available(self):
        return self.avail

