b2 = Book("To Kill a Mockingbird", "Harper Lee", "978-0061120084")

assert b1.mark_borrowed() == True
assert b1.mark_borrowed() == False
assert b1.get_info().endswith("Status: Borrowed")

assert b2.mark_returned() == False

b3 = Book("Dune", "Frank Herbert", "978-0441172719")
assert b3.is_available() == True

try:
