def log_arguments(sensitive_args=None):
    if sensitive_args is None:
        sensitive_args = []

    def decorator(func):
        func.call_log = []

        def wrapper(*args, **kwargs):
            log_entry = {'args': [], 'kwargs': {}, 'redacted': []}
            redacted = []

            for idx, val in enumerate(args):
                if idx in sensitive_args:
                    log_entry['args'].append('***')
                    redacted.append(f"arg_{idx}")
                else:
                    log_entry['args'].append(val)

            for key, val in kwargs.items():
                if key in sensitive_args:
                    log_entry['kwargs'][key] = '***'
                    redacted.append(key)
                else:
                    log_entry['kwargs'][key] = val

            log_entry['redacted'] = redacted
            func.call_log.append(log_entry)
            return func(*args, **kwargs)

        return wrapper

    return decorator


@log_arguments(sensitive_args=[0, 'password'])
