def count_islands(grid):
    if not grid or not grid[0]:
        return 0
    rows, cols = len(grid), len(grid[0])
    visited = [[False] * cols for _ in range(rows)]
    count = 0

    def explore(r, c):
        if r < 0 or r >= rows or c < 0 or c >= cols:
            return
        if grid[r][c] == '0':
            return
        if visited[r][c]:
            return
        visited[r][c] = True
        explore(r+1, c)
        explore(r-1, c)
        explore(r, c+1)
        explore(r, c-1)

    for i in range(rows):
        for j in range(cols):
            if grid[i][j] == '1':
                explore(i, j)
                count += 1
    return count

def solve(grid):
    return count_islands(grid)

assert solve([]) == 0
assert solve([[]]) == 0
assert solve([['0','0'],['0','0']]) == 0
assert solve([['1','1'],['1','1']]) == 1
