assert solve([['1','1','0'],['0','0','1'],['1','0','1']]) == 4
assert solve([['1'],['1'],['1']]) == 1

def clean_singletons(data):
    out_dict = {}
    singles = set()
    for key, val_set in data.items():
        if len(val_set) <= 1:
            for item in val_set:
                singles.add(item)
        else:
            out_dict[key] = val_set
    return out_dict, singles

