def analyze_transactions(transactions):
    totals = {}
    seen_users = set()

    for user_id, amount in transactions:
        if user_id in totals:
            totals[user_id] += amount
        else:
            totals[user_id] = amount
        seen_users.add(user_id)

    return totals

# Test cases
def run_tests():
    test1 = [(1, 10), (2, 20), (1, 5)]
    expected1 = {1: 15, 2: 20}
    result1 = analyze_transactions(test1)
    assert result1 == expected1, "Test case 1 failed"

    test2 = [(3, 5), (4, 10), (3, 3)]
    expected2 = {3: 8, 4: 10}
    result2 = analyze_transactions(test2)
    assert result2 == expected2, "Test case 2 failed"

    test3 = [(5, -2), (5, 7), (5, -3)]
    expected3 = {5: 2}
    result3 = analyze_transactions(test3)
    assert result3 == expected3, "Test case 3 failed"

run_tests()

def sort_books_by_popularity(books, popularity):
    def key_func(book):
        return (-popularity.get(book, 0), book)

    return sorted(books, key=key_func)

