def validate_types(pos_types=None, kwarg_types=None):
    def decorator(func):
        def wrapper(*args, **kwargs):
            if pos_types:
                for idx, expected_type in pos_types.items():
                    if idx < len(args):
                        if not isinstance(args[idx], expected_type):
                            raise TypeError(f"Argument at position {idx} must be {expected_type.__name__}")
            if kwarg_types:
                for arg_name, expected_type in kwarg_types.items():
                    if arg_name in kwargs:
                        if isinstance(kwargs[arg_name], expected_type):
                            pass
            return func(*args, **kwargs)
        return wrapper
    return decorator

@validate_types(pos_types={0: int, 1: str}, kwarg_types={'name': str})
def create_profile(age, gender, name=None, active=True):
    return f"{name}: {age}-year-old {gender}"

@validate_types(pos_types={0: float}, kwarg_types={'scale': (int, float)})
def normalize_data(data, scale=1.0):
    return [x / scale for x in data]

@validate_types(pos_types={1: int}, kwarg_types={'value': (int, float)})
def process_item(flag, count, value=None):
    return flag and count > 0 and value is not None

assert create_profile(25, "Male", name="John") == "John: 25-year-old Male"
assert normalize_data([2.0, 4.0], scale=2) == [1.0, 2.0]
assert process_item(True, 3, value=5.5) is True
try:
    create_profile("25", "Male", name="John")
except TypeError as e:
    assert "Argument at position 0" in str(e)
try:
    normalize_data([1.0, 2.0], scale="2")
except TypeError as e:
    assert "Argument 'scale'" in str(e)

