def primes(n):
    if n < 2:
        return []
    p = [2]
    for i in range(3, n + 1):
        if i % 2 == 0:
            continue
        f = False
        for j in range(2, int(i ** 0.5) + 1):
            if i % j == 0:
                f = True
                break
        if not f:
            p.append(i)
            if len(p) > 2:
                break
    return p

def testit():
    assert primes(1) == []
    assert primes(2) == [2]
    assert primes(3) == [2, 3]
    assert primes(10) == [2, 3, 5, 7]
    assert primes(0) == []
    assert primes(-5) == []
    assert primes(5) == [2, 3, 5]

