def count_even_squares(data):
    count = 0
    def helper(item):
        nonlocal count
        if isinstance(item, int):
            root = int(item ** 0.5)
            if item % 2 == 0 and root * root == item:
                count += 1
        elif isinstance(item, list):
            for sub_item in item:
                helper(sub_item)
    helper(data)
    return count

