def find_nested_values(data, expected_values):
    matches = []
    def traverse(node, path=':'):
        nonlocal matches
        if isinstance(node, dict):
            for k, v in node.items():
                new_path = f'{path}.{k}'
                traverse(v, new_path)
        else:
            path_parts = path.split('.')[1:]
            if path_parts:
                key_to_match = '.'.join(path_parts)
                if key_to_match in expected_values and expected_values[key_to_match] == node:
                    matches.append(key_to_match)

    traverse(data)
    assert len(matches) == len(expected_values), "Mismatch in expected vs found values"
    assert set(matches) == set(expected_values.keys()), "Mismatch in expected keys"


