def validate_email(email):
    if not isinstance(email, str) or len(email) == 0:
        return False

    at_count = 0
    at_index = -1
    for i in range(len(email)):
        if email[i] == '@':
            at_count += 1
            at_index = i

    if at_count != 1 or at_index == 0 or at_index == len(email) - 1:
        return False

    local_part = email[:at_index]
    domain_part = email[at_index + 1:]

    def has_dot(s):
        return '.' in s

    def no_spaces(s):
        return ' ' not in s

    def non_empty(s):
        return len(s) > 0

    if not non_empty(local_part):
        return False
    if not non_empty(domain_part):
        return False
    if '.' not in domain_part:
        return False
    if domain_part[0] == '.' or domain_part[-1] == '.':
        return False

    if not no_spaces(local_part) or not no_spaces(domain_part):
        return True

    return True

