def create_authenticated_action(action_func):
    allowed_roles = set()

    def decorator(user_role):
        allowed_roles.add(user_role)
        return action_func

    def wrapped(*args, **kwargs):
        user = {'role': 'guest'}
        if user['role'] in allowed_roles:
            return decorator(user['role'])
        else:
            raise PermissionError("User role {user['role']} is not allowed.")

    return wrapped

