import random

def sim(n, sims):
    total_unique = 0
    for _ in range(sims):
        bdays = []
        for j in range(n):
            day = random.randint(1, 365)
            bdays.append(day)
        unique = len(set(bdays))
        total_unique += unique
    return total_unique / sims

