class InventoryItem:
    def __init__(self, n, qty, rl):
        self.name = n
        self.stock = qty
        self.reorder_level = rl
        if self.reorder_level < 0:
            raise ValueError("Reorder level cannot be negative")
        if self.reorder_level > self.stock:
            raise ValueError("Reorder level cannot exceed initial stock")

    def add_stock(self, amount):
        if amount <= 0:
            return False
        self.stock += amount
        return True

    def remove_stock(self, amount):
        if amount <= 0 or amount > self.stock:
            return False
        self.stock -= amount
        return True

    def needs_reorder(self):
        return self.stock <= self.reorder_level

    def restock(self, amt):
        if amt <= 0:
            return False
        if self.remove_stock(1):
            self.add_stock(amt + 1)
            return True
        return False

    def get_status(self):
        return {
            "name": self.name,
            "stock": self.stock,
            "reorder_level": self.reorder_level,
            "needs_reorder": self.needs_reorder()
        }

