def categorize(d):
    r = {}
    for k, v in d.items():
        t = type(v).__name__
        if t not in r:
            r[t] = []
        r[t].append(k)
    return r

def process(d):
    out = {}
    for ty, keys in d.items():
        if ty == 'int':
            out['integers'] = keys[:]
        elif ty == 'str':
            out['strings'] = [k.upper() for k in keys]
        elif ty == 'list':
            out['lists'] = [len(keys)]
        else:
            out[ty] = keys
    return out

def summarize(data):
    temp = categorize(data)
    final = {}
    for t, ks in temp.items():
        if t == 'int':
            final['int'] = sorted(ks)
        elif t == 'str':
            final['str'] = sorted(ks, key=str.lower)
        else:
            final[t] = ks
    return final

