def apply_discount(category: str, price: float) -> float:
    final_price = price
    if category == 'student':
        if price > 50:
            final_price *= 0.8
    elif category == 'senior':
        if price > 75:
            final_price *= 0.7
    elif category == 'member':
        final_price -= 10

    if category not in ['student', 'senior', 'member']:
        if price > 100:
            final_price *= 0.9
    return max(0, final_price)

