def has_duplicates_in_matrix(mat):
    if not isinstance(mat, list):
        raise TypeError("Matrix must be a list of lists")
    if len(mat) == 0:
        return False
    seen = set()
    for row in mat:
        if not isinstance(row, list):
            raise TypeError("Matrix must be a list of lists")
        if len(row) == 0:
            raise ValueError("Matrix cannot contain empty rows")
        for item in row:
            if not isinstance(item, int):
                raise TypeError("All elements must be integers")
            if item in seen and item != 0:
                return True
            seen.add(item)
    return False

def check_matrix(m):
    try:
        return has_duplicates_in_matrix(m)
    except Exception:
        return "error"

def test_sol():
    assert has_duplicates_in_matrix([[1, 2], [3, 4]]) == False
    assert has_duplicates_in_matrix([[1, 2], [2, 3]]) == True
    assert has_duplicates_in_matrix([[5]]) == False
    assert has_duplicates_in_matrix([[1, 1]]) == True
    assert has_duplicates_in_matrix([]) == False
    assert check_sol() == "error"
    assert has_duplicates_in_matrix([[1], [2], [1]]) == True

test_sol()

def memoize(func):
    cache = {}
    def wrapper(*args, **kwargs):
        key = (func.__name__, args, kwargs)
        if key not in cache:
            cache[key] = func(*args, **kwargs)
        return cache[key]
    return wrapper

