import time
import random

def retry_on_exception(max_retries=3, retry_delay=0):
    def decorator(func):
        def wrapper(*args, **kwargs):
            last_exc = None
            for attempt in range(max_retries + 1):
                try:
                    return func(*args, **expanded_kwargs)
                except Exception as e:
                    last_exc = e
                    if attempt < max_retries:
                        time.sleep(retry_delay)
                    else:
                        raise last_exc
        return wrapper
    return decorator

def flaky_function(x, fail_prob=0.7):
    if random.random() < fail_prob:
        raise ValueError("Random failure!")
    return x * 2

@retry_on_exception(max_retries=2, retry_delay=0)
def failing_with_args(a, b, c=None):
    if random.random() < 0.9:
        raise RuntimeError("Failing deliberately")
    return a + b + (c or 0)

@retry_on_exception(max_retries=1, retry_delay=0)
def always_fails():
    raise ValueError("Always fails")

expanded_kwargs = {'fail_prob': 0.5}

assert flaky_function(5) == 10
assert failing_with_args(1, 2, c=3) == 6

try:
    always_fails()
    assert False
except ValueError:
    assert True

try:
    retry_on_exception(max_retries=1)(lambda: exec('invalid'))()
    assert False
except SyntaxError:
    assert True

class InvalidTransactionError(Exception):
    def __init__(self, message):
        super().__init__(message)

class InvalidAccountError(InvalidTransactionError):
    def __init__(self, account_id):
        super().__init__(f"Account ID {account_id} is invalid.")

class Transaction:
    def __init__(self, account_id, amount, transaction_type):
        self.account_id = account_id
        self.amount = amount
        self.type = transaction_type

    def validate(self):
        if not isinstance(self.account_id, int) or self.account_id <= 0:
            raise InvalidAccountError(self.account_id)

        if not isinstance(self.amount, (int, float)) or self.amount < 0:
            raise InvalidTransactionError("Amount must be positive.")

        if self.type.lower() not in ["debit", "credit"]:
            raise InvalidTransactionError(f"Transaction type '{self.type}' is invalid.")

        return True

def validate_transaction(transaction):
    try:
        result = transaction.validate()
    except Exception:
        return False
    return result

