def find_major(x):
    if not x:
        return None
    if len(x) == 1:
        return x[0]
    candidate = None
    count = 0
    for val in x:
        if count == 0:
            candidate = val
            count = 1
        elif val == candidate:
            count += 1
        else:
            count -= 1
    maj_count = 0
    for val in x:
        if val == candidate:
            maj_count += 1
    if maj_count >= len(x) // 2:
        return candidate
    return None

def solve_task_17(data):
    return find_major(data)

assert solve_task_17([3, 3, 4]) == 3
assert solve_task_17([]) is None
assert solve_task_17([1]) == 1
assert solve_task_17([1, 2, 3]) is None
assert solve_task_17([2, 2, 1, 1, 1, 2, 2]) == 2
assert solve_task_17([5, 5, 5, 5, 1]) == 5
assert solve_task_17([7, 1, 7, 2, 7]) == 7

def aggregate_data(data_list):
    result = {'weighted_average': 0.0, 'valid_records_count': 0, 'errors_encountered': []}
    sum_weights = 0.0
    sum_weighted_values = 0.0
    valid_count = 0

    for idx, record in enumerate(data_list):
        try:
            val = record['value']
            wt = record['weight']
            active_flag = record['active']

            if not isinstance(val, (int, float)):
                raise TypeError(f"Value not numeric: {val}")
            if not isinstance(wt, (int, float)):
                raise TypeError(f"Weight not numeric: {wt}")
            if wt <= 0:
                raise ValueError(f"Weight must be positive, got {wt}")
            if active_flag is not True:
                continue
            sum_weights += wt
            sum_weighted_values += val * wt
            valid_count += 1

        except KeyError as e:
            result['errors_encountered'].append(f"Missing key in record {idx}: {e}")
        except (TypeError, ValueError) as e:
            result['errors_encountered'].append(f"Invalid data in record {idx}: {e}")

    if sum_weights == 0:
        raise ValueError("No valid active records with positive weight found")

    weighted_avg = sum_weighted_values / sum_weights
    result['weighted_average'] = weighted_avg
    result['valid_records_count'] = valid_count
    return result


data1 = [
    {'value': 10, 'weight': 2, 'active': True},
    {'value': 20, 'weight': 3, 'active': True}
]
assert aggregate_data(data1)['weighted_average'] == 16.0

data2 = [
    {'value': 'x', 'weight': 1, 'active': True},
    {'weight': 2, 'active': True},
]
res2 = aggregate_data(data2)
assert res2['valid_records_count'] == 0
assert len(res2['errors_encountered']) == 2

data3 = [
    {'value': 5, 'weight': 0, 'active': True},
    {'value': 15, 'weight': 4, 'active': True},
]
res3 = aggregate_data(data3)
assert res3['weighted_average'] == 15.0
assert res3['valid_records_count'] == 1

def merge_dicts(*args, case_sensitive=True):
    for d in args:
        if not isinstance(d, dict):
            raise TypeError("All arguments must be dictionaries")
    result = {}
    for d in args:
        temp = {}
        for k, v in d.items():
            key = k.lower() if isinstance(k, str) and not case_sensitive else k
            temp[key] = v
        for k, v in temp.items():
            if k in result:
                continue
            result[k] = v
    return result

data1 = {"Name": "Alice", "age": 30}
data2 = {"name": "Bob", "AGE": 25}
data3 = {42: "answer", "Name": "Charlie"}

r1 = merge_dicts(data1, data2, case_sensitive=True)
r2 = merge_dicts(data1, data2, case_sensitive=False)
r3 = merge_dicts(data1, data3, case_sensitive=True)
r4 = merge_dicts({}, case_sensitive=False)
r5 = merge_dicts(data1, {"Name": "David"}, case_sensitive=False)

assert r1["name"] == "Bob"
assert "name" not in r2 and "Name" not in r2 and r2["name"] == "Bob"
assert r3[42] == "answer"
assert len(r4) == 0
assert r5["name"] == "David"
assert isinstance(r1, dict)
assert merge_dicts(data1, case_sensitive=True) == data1

def sort_files(file_list):
    def get_key(f):
        ext = f['extension']
        sz = f['size_kb']
        return (sz, ext)
    return sorted(file_list, key=get_key)

def process_data(lst):
    return sort_files(lst)

def example_usage():
    files = [
        {'filename': 'a.txt', 'size_kb': 20, 'extension': 'txt'},
        {'filename': 'b.pdf', 'size_kb': 10, 'extension': 'pdf'},
        {'filename': 'c.txt', 'size_kb': 5, 'extension': 'txt'},
        {'filename': 'd.pdf', 'size_kb': 30, 'extension': 'pdf'},
        {'filename': 'e.doc', 'size_kb': 15, 'extension': 'doc'},
        {'filename': 'f.txt', 'size_kb': 10, 'extension': 'txt'}
    ]
    return process_data(files)

def test_empty():
    return sort_files([])

def test_single():
    return sort_files([{'filename': 'x.log', 'size_kb': 5, 'extension': 'log'}])

result = example_usage()
empty_result = test_empty()
single_result = test_single()

assert result[0]['filename'] == 'e.doc'
assert result[1]['filename'] == 'b.pdf'
assert result[2]['filename'] == 'd.pdf'
assert result[3]['filename'] == 'c.txt'
assert result[4]['filename'] == 'f.txt'
assert result[5]['filename'] == 'a.txt'
assert len(empty_result) == 0
assert single_result[0]['filename'] == 'x.log'

