def calculate_discount(customer_type, amount):
    if amount < 0:
        return 0
    if customer_type == 'premium':
        if amount >= 100:
            amount *= 0.9
    elif customer_type == 'vip':
        if amount >= 200:
            amount *= 0.8
    elif customer_type == 'regular':
        if amount > 150:
            amount *= 0.95
    return round(amount)

