def create_filtered_generator(seq, condition):
    def generator():
        for item in seq:
            if condition(item):
                yield item
    return generator()

def make_filter_chain(data, *filters):
    if not filters:
        return iter(data)
    gen = create_filtered_generator(data, filters[0])
    for f in filters[1:]:
        gen = create_filtered_generator(data, f)
    return gen

