class CumulativeSum好处:
    def __init__(self, data):
        self.data = iter(data)
        self.total = 0
        self.started = False

    def __iter__(self):
        return self

    def __next__(self):
        try:
            val = next(self.data)
            if not self.started:
                self.total = val
                self.started = True
            self.total += val
            return self.total
        except StopIteration:
            raise StopIteration

