def parse_range_string(s):
    if not s or '=' not in s or ',' not in s:
        raise ValueError("invalid format: must contain 'start=' and 'end=' separated by comma")
    try:
        parts = s.split(',')
        start_part = parts[0].strip()
        end_part = parts[1].strip()
        if not start_part.startswith('start=') or not end_part.startswith('end='):
            raise ValueError("missing 'start=' or 'end=' prefix")
        start_val_str = start_part.split('=')[1]
        end_val_str = end_part.split('=')[1]
        if not start_val_str.isdigit() and not (start_val_str[0] == '-' and start_val_str[1:].isdigit()):
            raise ValueError("start value is not a valid integer")
        if not end_val_str.isdigit() and not (end_val_str[0] == '-' and end_val_str[1:].isdigit()):
            raise ValueError("end value is not a valid integer")
        start_val = int(start_val_str)
        end_val = int(end_val_str)
        if start_val > end_val:
            raise ValueError("start value must be less than or equal to end value")
        return list(range(start_val, end_val))  
    except IndexError:
        raise ValueError("malformed string: missing start or end part")
    except Exception as e:
        if isinstance(e, ValueError):
            raise e
        else:
            raise ValueError("parsing failed due to invalid input format")

