def retry(max_retries=3):
    def decorator(func):
        retry_count = max_retries
        def wrapper(*args, **kwargs):
            nonlocal retry_count
            attempts = max_retries
            while attempts > 0:
                try:
                    return func(*args, **kwargs)
                except ValueError:
                    retry_count -= 1
                    attempts -= 1
            return func(*args, **kwargs)
        wrapper.retry_count = retry_count
        return wrapper
    return decorator

def test_retry():
    @retry(max_retries=3)
    def failing_func():
        raise ValueError()

    try:
        failing_func()
    except ValueError:
        assert hasattr(failing_func, 'retry_count'), "Retry count attribute should exist"
        assert failing_func.retry_count == 0, "Expected 1 retries, got {}.".format(failing_func.retry_count)

