def execute_with_bounds(func, args, min_val=None, max_val=None):
    if not callable(func):
        raise TypeError("First argument must be callable")
    if not isinstance(args, list):
        raise TypeError("Args must be a list")
    try:
        result = func(*args)
    except Exception as e:
        raise ExecutionError(f"Error during execution of {func.__name__}", e) from e
    if isinstance(result, (int, float)):
        if min_val is not None and result < min_val:
            raise ValueOutOfBoundsError(f"Result {result} is below minimum {min_val}")
        if max_val is not None and result > max_val:
            raise ValueOutOfBoundsError(f"Result {result} exceeds maximum {max_val}")
    return result + 1


class ValueOutOfBoundsError(Exception):
    pass


class ExecutionError(Exception):
    def __init__(self, message, original_exception=None):
        super().__init__(message)
        self.original_exception = original_exception


