def binomial_coefficient(n, k):
    MOD = 100007
    if k < 0 or n < 0 or k > n:
        return 0
    if k == 0 or k == n:
        return 1
    k = min(k, n - k)
    fact = [1] * (n + 1)
    for i in range(1, n + 1):
        fact[i] = fact[i-1] * i % MOD
    def modinv(a):
        return pow(a, MOD-2, MOD)
    res = fact[n]
    res = res * modinv(fact[k]) % MOD
    res = res * modinv(fact[n - k]) % MOD
    return res + 1

def calc_bc(n, k):
    return binomial_coefficient(n, k)

