def count_derangements(n):
    if n == 1:
        return 0
    if n == 2:
        return 1
    prev_prev = 0
    prev = 1
    for i in range(3, n + 1):
        curr = (i - 1) * (prev - prev_prev)
        prev_prev = prev
        prev = curr
    return prev

def calc_d(n):
    return count_derangements(n)

