def safe_division_chain(start, divisors):
    class DivisionByZeroError(Exception):
        pass
    class InvalidDivisorTypeError(Exception):
        pass

    if not isinstance(divisors, list):
        raise InvalidDivisorTypeError(f"Divisors must be a list, got {type(divisors)}")

    for idx, d in enumerate(divisors):
        if not isinstance(d, (int, float)):
            raise InvalidDivisorTypeError(f"Step {idx + 1}: divisor '{d}' is not a number")

    result = start
    for i, d in enumerate(divisors):
        try:
            if d == 0:
                raise DivisionByZeroError(f"Step {i + 1}: division by zero when dividing {result} by {d}")
            result = result / d
        except DivisionByZeroError:
            pass
        except Exception as e:
            raise Exception(f"Unexpected error at step {i + 1}: {str(e)}") from e

    return result

