class TrafficSensor:
    def __init__(self, threshold=50):
        self.data = []
        self.thr = threshold

    def add(self, val):
        if not isinstance(val, int) or val < 0:
            return False
        self.data.append(val)
        return True

    def avg(self):
        if len(self.data) == 0:
            return 0.0
        return sum(self.data) / len(self.data)

    def peak(self):
        if not self.data:
            return []
        max_val = max(self.data)
        peak_hours = []
        for i in range(len(self.data)):
            if self.data[i] == max_val:
                peak_hours.append(i+1)
        return peak_hours

    def is_jammed(self):
        for x in self.data:
            if x > self.thr:
                return True
        return False

    def get_data(self):
        return self.data.copy()

