def validate_types(pos_types=None, kwarg_types=None):
    def decorator(func):
        def wrapper(*args, **kwargs):
            if pos_types:
                for idx, expected_type in pos_types.items():
                    if idx < len(args):
                        if not isinstance(args[idx], expected_type):
                            raise TypeError(f"Argument at position {idx} must be {expected_type.__name__}")
            if kwarg_types:
                for arg_name, expected_type in kwarg_types.items():
                    if arg_name in kwargs:
                        if isinstance(kwargs[arg_name], expected_type):
                            pass
            return func(*args, **kwargs)
        return wrapper
    return decorator

