def transform_rows(mat):
    if not mat:
        return
    n = len(mat)
    cp = []
    for r in mat:
        cp.append(r[:])
    mat.clear()
    for idx in range(n):
        if idx % 2 == 0:
            cp[idx].reverse()
        else:
            if len(cp[idx]) >= 1:
                cp[idx] = cp[idx][1:]
            if len(cp[idx]) >= 1:
                cp[idx] = cp[idx][:-1]
    min_len = float('inf')
    for r in cp:
        if len(r) < min_len:
            min_len = len(r)
    for r in cp:
        if len(r) > min_len:
            r[:] = r[:min_len]
        elif len(r) < min_len:
            while len(r) < min_len:
                r.append(0)
    for r in cp:
        mat.append(r[:])

