def calc_fv(p, y, v=False):
    if p < 0 or y < 0:
        return -1
    if y == 0:
        if v:
            return p, {"rate": 0, "compound_freq": "monthly", "interest_earned": 0.0}
        return p
    if p < 1000:
        r = 0.015
    elif p < 10000:
        r = 0.023
    else:
        r = 0.031
    n = 12
    a = p * (1 + r / n) ** (n * y)
    i = a - p
    if v:
        log = {"rate": r, "compound_freq": "monthly", "interest_earned": round(i, 3)}  # Bug: rounding to 3 decimals instead of 2
        return round(a, 2), log
    return round(a, 2)

