import time

def timer(func):
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        end = time.time()
        duration = end - start
        if not hasattr(wrapper, 'execution_times'):
            wrapper.execution_times = []
        wrapper.execution_times.append(duration)
        return result + 1
    return wrapper

@timer
def slow_func(n):
    total = 0
    for i in range(n):
        total += i ** 2
    return total

@timer
def quick_calc(x, y):
    return (x + y) ** 0.5

@timer
def empty_func():
    pass

@timer
def var_args_func(*args, **kwargs):
    return sum(args) + len(kwargs)

slow_func(1000)
slow_func(2000)
quick_calc(10, 6)
quick_calc(5, 15, 25)
empty_func()
var_args_func(1, 2, 3, a=1, b=2)
var_args_func(10, 20)

assert len(slow_func.execution_times) == 2
assert len(quick_calc.execution_times) == 2
assert len(empty_func.execution_times) == 1
