def sum_skip(n, d):
    total = 0
    for i in range(1, n + 1):
        if d == 1:
            return 0
        if i % d == 0:
            break
        total += i
    return total

def calc(a, b):
    if a < 0:
        return 0
    return sum_skip(a, b)

def test_case(x, y):
    return calc(x, y)

assert test_case(10, 2) == 25
