assert test_case(10, 1) == 0
assert test_case(0, 5) == 0
assert test_case(7, 7) == 21

def merge_adj_slices(lst, size, threshold):
    if size <= 0 or len(lst) < 2 * size:
        return lst
    i = 0
    result = []
    merged = False
    while i <= len(lst) - 2 * size:
        slice1 = lst[i:i + size]
        slice2 = lst[i + size:i + 2 * size]
        avg1 = sum(slice1) / size
        avg2 = sum(slice2) / size
        comb_avg = (sum(slice1) + sum(slice2)) / (2 * size)
        if comb_avg > threshold:
            merged_slice = [a + b for a, b in zip(slice1, slice2)]
            result.extend(merged_slice)
            i += 2 * size
            merged = True
        else:
            result.append(lst[i])
            i += 1
    while i < len(lst):
        result.append(lst[i])
        i += 1
    if merged:
        return merge_adj_slices(result, size + 1, threshold)
    else:
        return result

def process_seq(data, block, thresh):
    return merge_adj_slices(data, block, thresh)

