    if not callable(f):
        raise TypeError("func must be callable")
    if not isinstance(mr, int) or mr < 0:
        raise TypeError("max_retries must be non-negative integer")
    if not isinstance(ewl, tuple) or not all(issubclass(e, BaseException) for e in ewl):
        raise TypeError("exception_whitelist must be tuple of exception types")
    retries = 0
    while True:
        try:
            return f()
        except Exception as e:
            if type(e) not in ewl:
