def update_book_catalog(catalog, updates):
    updated = catalog.copy()
    for title, data in updates.items():
        if title in updated:
            updated[title].update(data)
        else:
            updated[title] = data
    return updated

# Test cases
def test_update_book_catalog():
    catalog = {
        "Book A": {"author": "Alice", "rating": 4.5},
        "Book B": {"author": "Bob", "rating": 3.0}
    }

    updates = {
        "Book A": {"rating": 4.8},
        "Book C": {"author": "Charlie"}
    }

    result = update_book_catalog(catalog, updates)

    assert result["Book A"]["author"] == "Alice", "Test case 1"
    assert result["Book A"]["rating"] == 4.8, "Test case 2"
    assert result["Book C"]["author"] == "Charlie", "Test case 3"
    assert "Book B" in result and result["Book B"]["author"] == "Bob", "Test case 4"

    print("All tests passed!")

