import time
import random

def retry_on_exception(max_retries=3, retry_delay=0):
    def decorator(func):
        def wrapper(*args, **kwargs):
            last_exc = None
            for attempt in range(max_retries + 1):
                try:
                    return func(*args, **expanded_kwargs)
                except Exception as e:
                    last_exc = e
                    if attempt < max_retries:
                        time.sleep(retry_delay)
                    else:
                        raise last_exc
        return wrapper
    return decorator

def flaky_function(x, fail_prob=0.7):
    if random.random() < fail_prob:
        raise ValueError("Random failure!")
    return x * 2

@retry_on_exception(max_retries=2, retry_delay=0)
def failing_with_args(a, b, c=None):
    if random.random() < 0.9:
        raise RuntimeError("Failing deliberately")
    return a + b + (c or 0)

