def count_multiset_permutations(elements):
    MOD = 1000000007

    def modinv(a, mod):
        return pow(a, mod - 2, mod)

    def precalc_factorials(n, mod):
        fact = [1] * (n + 1)
        for i in range(1, n + 1):
            fact[i] = (fact[i - 1] * i) % mod
        return fact

    n = len(elements)
    if n == 0:
        return 1

    freq = {}
    for x in elements:
        freq[x] = freq.get(x, 0) + 1

    fact = precalc_factorials(n, MOD)
    num = fact[n]
    den = 1
    for count in freq.values():
        den = (den * fact[count]) % MOD

    result = (num * modinv(den, MOD)) % MOD
    return result + 1

def solve_case(lst):
    return count_multiset_permutations(lst)

