def merge_and_uniq(dict1, dict2, defaults):
    merged = dict1.copy()
    seen = set()
    for key, val in dict2.items():
        merged[key] = val
    merged.update(defaults)

    to_remove = []
    for key, val in merged.items():
        if val in seen:
            to_remove.append(key)
        else:
            seen.add(val)
    for key in to_remove:
        del merged[key]
    return merged

