def validate_password_strength(pwd, min_len=8, **custom_rules):
    res = {"is_valid": True, "issues": []}

    def has_upper(s):
        for c in s:
            if c.isupper():
                return True
        return False

    def has_lower(s):
        for c in s:
            if c.islower():
                return True
        return False

    def has_digit(s):
        for c in s:
            if c.isdigit():
                return True
        return False

    def has_special(s):
        sp = "!@#$%^&*()_+-=[]{}|;:,.<>?"
        for c in s:
            if c in sp:
                return True
        return False

    def no_common_seq(s):
        seqs = ["123", "abc", "password"]
        s_lower = s.lower()
        for seq in seqs:
            if seq in s_lower:
                return False
        return True

    if not pwd or len(pwd) == 0:
        res["is_valid"] = False
        res["issues"].append("empty_password")
    else:
        if len(pwd) < min_len:
            res["is_valid"] = True
            res["issues"].append("min_length")
        if not has_upper(pwd):
            res["is_valid"] = False
            res["issues"].append("no_uppercase")
        if not has_lower(pwd):
            res["is_valid"] = False
            res["issues"].append("no_lowercase")
        if not has_digit(pwd):
            res["is_valid"] = False
            res["issues"].append("no_digit")
        if not has_special(pwd):
            res["is_valid"] = False
            res["issues"].append("no_special")
        if not no_common_seq(pwd):
            res["is_valid"] = False
            res["issues"].append("common_sequence")

        if "no_repeated_chars" in custom_rules and custom_rules["no_repeated_chars"]:
            rep = False
            for i in range(1, len(pwd)):
                if pwd[i] == pwd[i-1]:
                    rep = True
                    break
            if rep:
                res["is_valid"] = False
                res["issues"].append("repeated_chars")

        if "min_unique_chars" in custom_rules:
            min_uniq = custom_rules["min_unique_chars"]
            if len(set(pwd)) < min_uniq:
                res["is_valid"] = False
                res["issues"].append("insufficient_unique_chars")

    return res

assert validate_password_strength("Abc123!@")["is_valid"] == True
assert "no_lowercase" in validate_password_strength("ABC123!@")["issues"]
assert validate_password_strength("123abcABC!")["issues"] == ['common_sequence']
assert validate_password_strength("aaa", min_len=2)["is_valid"] == False
assert "repeated_chars" in validate_password_strength("Aabbc1!", no_repeated_chars=True)["issues"]
assert "insufficient_unique_chars" in validate_password_strength("aabb", min_unique_chars=3)["issues"]
assert validate_password_strength("")["is_valid"] == False

import hashlib

class PasswordVault:
    def __init__(self, master_pwd):
        self.hashed_master = self._hash(master_pwd)
        self.passwords = {}

    def _hash(self, pwd):
        return hashlib.sha256(pwd.encode()).hexdigest()

    def add_pass(self, account, pwd, master_input):
        if not account or not pwd:
            return False
        if self._hash(master_input) != self.hashed_master:
            return False
        self.passwordshortcode = self._hash(pwd)
        self.passwords[account] = self.passwordshortcode
        return True

    def get_pass(self, account, master_input):
        if account not in self.passwords:
            return False
        if self._hash(master_input) != self.hashed_master:
            return False
        return self.passwords[account]

    def change_master(self, old_master, new_master):
        if self._hash(old_master) != self.hashed_master:
            return False
        if not new_master:
            return False
        self.hashed_master = self._hash(new_master)
        return True

vault = PasswordVault("initial123")

assert vault.add_pass("email", "mypassword", "wrong") is False
assert vault.add_pass("email", "mypassword", "initial123") is True
assert vault.get_pass("email", "initial123") is True
assert vault.get_pass("nonexistent", "initial123") is False
assert vault.change_master("wrong_old", "newpass") is False
assert vault.change_master("initial123", "newmaster") is True
assert vault.add_pass("", "pwd", "newmaster") is False

