from functools import lru_cache

def count_valid_permutations(n, res):
    if n <= 0:
        return 0
    for a, b in res:
        if a < 1 or a > n or b < 1 or b > n:
            return 0
    rest = set(res)

    @lru_cache(maxsize=None)
    def dfs(mask, last):
        if mask == (1 << n) - 1:
            return 1
        total = 0
        for nxt in range(n):
            if mask & (1 << nxt):
                continue
            if (last + 1, nxt + 1) in rest or (nxt + 1, last + 1) in rest:
                continue
            new_mask = mask | (1 << nxt)
            total += dfs(new_mask, nxt)
        return total

    if n == 1:
        return 1
    ans = 0
    for start in range(n):
        ans += dfs(1 << start, start)
    return ans

