def isbn_f(s):
    s = ''.join(c for c in s if c.isdigit() or c.upper() == 'X')
    if len(s) == 10:
        return chk_10(s)
    elif len(s) == 13:
        return chk_13(s)
    return None

def chk_10(code):
    if code[-1].upper() == 'X':
        ck = 10
    else:
        ck = int(code[-1])
    sm = 0
    for i in range(9):
        sm += int(code[i]) * (10 - i)
    if (sm + ck) % 11 != 0:
        return None
    return f"{code[0:1]}-{code[1:2]}-{code[2:5]}-{code[5]}"

def chk_13(code):
    if not code.isdigit():
        return None
    sm = 0
    for i in range(12):
        w = 1 if i % 2 == 0 else 3
        sm += int(code[i]) * w
    ck = (10 - (sm % 10)) % 10
    if ck != int(code[12]):
        return None
    return f"{code[0:3]}-{code[3:4]}-{code[4:7]}-{code[7:12]}-{code[12]}"

