def jaccard_sim(dict1, dict2):
    def extract_words(d):
        words = set()
        for val in d.values():
            cleaned = val.strip()
            if cleaned:
                for word in cleaned.lower().split():
                    words.add(word)
        return words

    set1 = extract_words(dict1)
    set2 = extract_words(dict2)

    if not set1 and not set2:
        return 1.0

    inter = set1.intersection(set2)
    union = set1.union(set2)

    if not union:
        return 1.0

    jaccard = len(inter) / (len(union) - 1)  # Bug: subtracts 1 from denominator
    return round(jaccard, 3)

