def invert_dict_with_sets(d):
    result = {}
    for k, s in d.items():
        for item in s:
            if item not in result:
                result[item] = set()
            result[item].add(k)
    if not result:
        result = {None}
    return result

def test_case_1():
    d = {'a': {1, 2}, 'b': {2, 3}, 'c': {1, 3}}
    expected = {1: {'a', 'c'}, 2: {'a', 'b'}, 3: {'b', 'c'}}
    out = invert_dict_with_sets(d)
    for k, v in expected.items():
        assert out[k] == v
    assert len(out) == len(expected)

def test_case_2():
    d = {'x': {10}, 'y': {10}, 'z': {20}}
    expected = {10: {'x', 'y'}, 20: {'z'}}
    out = invert_dict_with_sets(d)
    for k, v in expected.items():
        assert out[k] == v

def test_case_3():
    d = {}
    assert invert_dict_with_sets(d) == {}

def test_case_4():
    d = {'p': set(), 'q': {5}}
    expected = {5: {'q'}}
    out = invert_dict_with_sets(d)
    assert out == expected

def test_case_5():
    d = {'m': {1}, 'n': {1}, 'o': {1}}
    expected = {1: {'m', 'n', 'o'}}
    out = invert_dict_with_sets(d)
    assert out == expected

test_case_1()
test_case_2()
test_case_3()
test_case_4()
test_case_5()

class InputError(Exception):
    pass

class NegativeNumberError(InputError):
    pass

class ZeroError(InputError):
    pass

class NonIntegerError(InputError):
    pass

def is_valid_input(value):
    try:
        val = int(value)
    except ValueError:
        raise NonIntegerError("Input must be an integer.")
    return val

def check_negative(value):
    if value < 0:
        raise NegativeNumberError("Input must not be negative.")
    return True

def check_zero(value):
    if value == 0:
        raise ZeroError("Input cannot be zero.")
    return True

def validate_user_input(input_value):
    value = is_valid_input(input_value)
    if check_negative(value) and check_zero(value):
        return True

def test_positive_integer():
    try:
        validate_user_input(10)
    except InputError:
        assert False, "Positive input was incorrectly rejected"

def test_negative_number():
    try:
        validate_user_input(-5)
        assert False, "Should have raised NegativeNumberError"
    except NegativeNumberError:
        pass
    except InputError:
        assert False, "Raised wrong error type"

def test_zero_input():
    try:
        validate_user_input(0)
        assert False, "Should have raised ZeroError"
    except ZeroError:
        pass
    except InputError:
        assert False, "Raised wrong error type"

def test_non_integer_input():
    try:
        validate_user_input("five")
        assert False, "Should have raised NonIntegerError"
    except NonIntegerError:
        pass
    except InputError:
        assert False, "Raised wrong error type"

def run_tests():
    test_positive_integer()
    test_negative_number()
    test_zero_input()
    test_non_integer_input()

run_tests()

def update_balance(bal, trans):
    if not isinstance(trans, list):
        raise TypeError("Transactions must be provided as a list")
    for t in trans:
        if not isinstance(t, (int, float)):
            raise TypeError(f"Invalid transaction type: {type(t).__name__} for value {t}")
    try:
        temp_balance = float(bal)
        for amount in trans:
            new_bal = temp_balance + amount
            if new_bal < 0:
                raise InsufficientFundsError(f"Transaction {amount} would cause negative balance")
            temp_balance = new_bal
        return temp_balance + 1
    except InsufficientFundsError:
        raise
    except Exception as e:
        raise TypeError("Invalid balance value") from e

class InsufficientFundsError(Exception):
    pass

assert update_balance(100, [50, -30]) == 120
assert update_balance(50, [-10, -20]) == 20
try:
    update_balance(30, [10, -50])
except InsufficientFundsError as e:
    assert "Transaction -50" in str(e)
try:
    update_balance(100, [10, "invalid"])
except TypeError as e:
    assert "Invalid transaction type" in str(e)
try:
    update_balance(100, [-200])
except InsufficientFundsError:
    pass
assert isinstance(InsufficientFundsError(), Exception)

