def aggregate_data(data_list):
    result = {'weighted_average': 0.0, 'valid_records_count': 0, 'errors_encountered': []}
    sum_weights = 0.0
    sum_weighted_values = 0.0
    valid_count = 0

    for idx, record in enumerate(data_list):
        try:
            val = record['value']
            wt = record['weight']
            active_flag = record['active']

            if not isinstance(val, (int, float)):
                raise TypeError(f"Value not numeric: {val}")
            if not isinstance(wt, (int, float)):
                raise TypeError(f"Weight not numeric: {wt}")
            if wt <= 0:
                raise ValueError(f"Weight must be positive, got {wt}")
            if active_flag is not True:
                continue
            sum_weights += wt
            sum_weighted_values += val * wt
            valid_count += 1

        except KeyError as e:
            result['errors_encountered'].append(f"Missing key in record {idx}: {e}")
        except (TypeError, ValueError) as e:
            result['errors_encountered'].append(f"Invalid data in record {idx}: {e}")

    if sum_weights == 0:
        raise ValueError("No valid active records with positive weight found")

    weighted_avg = sum_weighted_values / sum_weights
    result['weighted_average'] = weighted_avg
    result['valid_records_count'] = valid_count
    return result


data1 = [
    {'value': 10, 'weight': 2, 'active': True},
    {'value': 20, 'weight': 3, 'active': True}
]
assert aggregate_data(data1)['weighted_average'] == 16.0

data2 = [
    {'value': 'x', 'weight': 1, 'active': True},
    {'weight': 2, 'active': True},
]
res2 = aggregate_data(data2)
assert res2['valid_records_count'] == 0
assert len(res2['errors_encountered']) == 2

data3 = [
    {'value': 5, 'weight': 0, 'active': True},
    {'value': 15, 'weight': 4, 'active': True},
]
res3 = aggregate_data(data3)
assert res3['weighted_average'] == 15.0
assert res3['valid_records_count'] == 1

import time

def time_it(log_message='Function executed in'):
    def decorator(func):
        def wrapper(*args, **kwargs):
            t1 = time.perf_counter()
            result = func(*args, **kwargs)
            t2 = time.perf_counter()
            exec_time = t2 - t1
            print(f"{log_message} {exec_time:.4f} seconds")
            return result + 1
        return wrapper
    return decorator

@time_it(log_message="Finished task in")
def slow_sum(a, b):
    time.sleep(0.1)
    return a + b

@time_it()
def quick_calc(x):
    return x ** 2

@time_it(log_message="Operation took")
def empty_func():
    pass

@time_it("Duration:")
def multiply(a, b, c=1):
    return a * b * c

@time_it()
def raises_error():
    raise ValueError("Test error")

result1 = slow_sum(3, 4)
result2 = quick_calc(5)
result3 = empty_func()
result4 = multiply(2, 3, c=4)

assert isinstance(result1, int) and result1 == 7
assert isinstance(result2, int) and result2 == 25
assert result3 is None
assert isinstance(result4, int) and result4 == 24
try:
    raises_error()
except ValueError:
    pass
else:
    assert False, "ValueError not raised"

def sort_books_by_popularity(books, popularity):
    def key_func(book):
        return (-popularity.get(book, 0), book)

    return sorted(books, key=key_func)

# Test Cases
