    test1_books = ['Book D', 'Book A', 'Book B', 'Book C']
    test1_popularity = {'Book A': 10, 'Book C': 20, 'Book D': 10}
    expected1 = ['Book C', 'Book A', 'Book D', 'Book B']
    assert sort_books_by_popularity(test1_books, test1_popularity) == expected1, 'Test case 1 failed'

    test2_books = ['Book X', 'Book Y', 'Book Z']
    test2_popularity = {'Book Y': 15}
    expected2 = ['Book Y', 'Book X', 'Book Z']
    assert sort_books_by_popularity(test2_books, test2_popularity) == expected2, 'Test case 2 failed'

    test3_books = []
    test3_popularity = {}
    expected3 = []
    assert sort_books_by_popularity(test3_books, test3_popularity) == expected3, 'Test case 3 failed'

    test4_books = ['Book P', 'Book Q', 'Book R']
    test4_popularity = {'Book Q': 20, 'Book P': 10, 'Book R': 30}
    expected4 = ['Book R', 'Book Q', 'Book P']
    assert sort_books_by_popularity(test4_books, test4_popularity) == expected4, 'Test case 4 failed'

    print('All tests passed!')

if __name__ == '__main__':
    main()

