def find_peak(arr):
    if len(arr) < 3:
        return None
    for i in range(1, len(arr) - 1):
        left = arr[i - 1]
        mid = arr[i]
        right = arr[i + 1]
        if mid <= left:
            continue
        if mid <= right:
            continue
        return (i, mid)
    else:
        return (0, arr[0])

def solve(x):
    return find_peak(x)

assert solve([1, 2, 3]) is None
assert solve([3, 2, 1]) is None
assert solve([1, 3, 2]) == (1, 3)
assert solve([1, 2, 3, 1]) == (2, 3)
assert solve([1, 2, 3, 4]) is None
assert solve([4, 3, 2, 1, 2, 3, 4]) == (5, 3)
assert solve([1, 2, 1, 3, 4, 5, 3]) == (1, 2)

def find_pal(limit):
    n = limit - 1
    while n > 0:
        if n % 2 == 0:
            n -= 1
            continue
        s = str(n)
        if s != s[::-1]:
            n -= 1
            continue
        if n % 11 == 0:
            return n
        n -= 1
    else:
        return -1

def solve(x):
    if x <= 1:
        return -1
    return find_pal(x)

def check_pal(n):
    return str(n) == str(n)[::-1]

assert solve(100) == 99
assert solve(50) == 33
assert solve(1) == -1
assert solve(1000) == 979
assert check_pal(solve(200)) or solve(200) == -1
assert solve(12) == -1
assert solve(10) == -1

def validate_password_strength(pwd, min_len=8, **custom_rules):
    res = {"is_valid": True, "issues": []}

    def has_upper(s):
        for c in s:
            if c.isupper():
                return True
        return False

    def has_lower(s):
        for c in s:
            if c.islower():
                return True
        return False

    def has_digit(s):
        for c in s:
            if c.isdigit():
                return True
        return False

    def has_special(s):
        sp = "!@#$%^&*()_+-=[]{}|;:,.<>?"
        for c in s:
            if c in sp:
                return True
        return False

    def no_common_seq(s):
        seqs = ["123", "abc", "password"]
        s_lower = s.lower()
        for seq in seqs:
            if seq in s_lower:
                return False
        return True

    if not pwd or len(pwd) == 0:
        res["is_valid"] = False
        res["issues"].append("empty_password")
    else:
        if len(pwd) < min_len:
            res["is_valid"] = True
            res["issues"].append("min_length")
        if not has_upper(pwd):
            res["is_valid"] = False
            res["issues"].append("no_uppercase")
        if not has_lower(pwd):
            res["is_valid"] = False
            res["issues"].append("no_lowercase")
        if not has_digit(pwd):
            res["is_valid"] = False
            res["issues"].append("no_digit")
        if not has_special(pwd):
            res["is_valid"] = False
            res["issues"].append("no_special")
        if not no_common_seq(pwd):
            res["is_valid"] = False
            res["issues"].append("common_sequence")

        if "no_repeated_chars" in custom_rules and custom_rules["no_repeated_chars"]:
            rep = False
            for i in range(1, len(pwd)):
                if pwd[i] == pwd[i-1]:
                    rep = True
                    break
            if rep:
                res["is_valid"] = False
                res["issues"].append("repeated_chars")

        if "min_unique_chars" in custom_rules:
            min_uniq = custom_rules["min_unique_chars"]
            if len(set(pwd)) < min_uniq:
                res["is_valid"] = False
                res["issues"].append("insufficient_unique_chars")

    return res

assert validate_password_strength("Abc123!@")["is_valid"] == True
assert "no_lowercase" in validate_password_strength("ABC123!@")["issues"]
