def calc_age(birth_dict):
    curr_y, curr_m, curr_d = 2023, 10, 15
    by = birth_dict['year']
    bm = birth_dict['month']
    bd = birth_dict['day']

    if by > curr_y or (by == curr_y and bm > curr_m) or (by == curr_y and bm == curr_m and bd > curr_d):
        raise ValueError("Birthdate is in the future")

    if bm < 1 or bm > 12:
        raise ValueError("Invalid month")

    days_in_month = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
    if by % 4 == 0 and (by % 100 != 0 or by % 400 == 0):
        days_in_month[1] = 29
    else:
        days_in_month[1] = 28

    if bd < 1 or bd > days_in_month[bm - 1]:
        raise ValueError("Invalid day for given month and year")

    y_diff = curr_y - by
    m_diff = curr_m - bm
    d_diff = curr_d - bd

    if d_diff < 0:
        m_diff -= 1
        prev_month = curr_m - 1 if curr_m > 1 else 12
        prev_year = curr_y if curr_m > 1 else curr_y - 1
        days_in_prev = 31
        if prev_month == 2:
            if (prev_year % 4 == 0 and prev_year % 100 != 0) or (prev_year % 400 == 0):
                days_in_prev = 29
            else:
                days_in_prev = 28
        elif prev_month in [4,6,9,11]:
            days_in_prev = 30
        else:
            days_in_prev = 31
        d_diff += days_in_prev

    if m_diff < 0:
        y_diff -= 1
        m_diff += 12

    return {'years': y_diff, 'months': m_diff, 'days': d_diff + 1}

