import signal
import time
from functools import wraps

def limit_time(t):
    def deco(f):
        @wraps(f)
        def w(*args, **kwargs):
            def handler(signum, frame):
                raise TimeoutError(f"Function {f.__name__} exceeded time limit of {t} seconds")
            old_sig = signal.signal(signal.SIGALRM, handler)
            signal.alarm(t)
            try:
                result = f(*args, **kwargs)
                signal.alarm(0)
                return result
            except Exception as e:
                signal.alarm(0)
                signal.signal(signal.SIGALRM, old_sig)
                raise
            signal.alarm(0)
            signal.signal(signal.SIGALRM, old_sig)
            return result
        return w
    return deco

