def convert_to_seconds(data):
    valid_units = {'days', 'hours', 'minutes', 'seconds'}
    conversion_factors = {'days': 86400, 'hours': 3600, 'minutes': 60, 'seconds': 1}
    total = 0.0

    if not isinstance(data, dict):
        raise TypeError("Input must be a dictionary")

    for key in data:
        if key not in valid_units:
            raise KeyError(f"Invalid unit: {key}")
        val = data[key]
        if not isinstance(val, (int, float)):
            raise TypeError(f"Value for {key} must be a number")
        if val < 0:
            raise ValueError(f"Value for {key} cannot be negative")
        total += val * conversion_factors[key]

    return round(total, 1)

def test_case():
    res1 = convert_to_seconds({'days': 1, 'hours': 2, 'minutes': 30, 'seconds': 15.5})
    assert res1 == 95415.5, f"Test 1 failed: {res1}"

    res2 = convert_to_seconds({'hours': 0, 'minutes': 0, 'seconds': 0})
    assert res2 == 0.0, f"Test 2 failed: {res2}"

    try:
        convert_to_seconds({'weeks': 1})
        assert False, "Test 3 failed: should raise KeyError"
    except KeyError:
        pass

    try:
        convert_to_seconds({'days': -1})
        assert False, "Test 4 failed: should raise ValueError"
    except ValueError:
        pass

    try:
        convert_to_seconds({'minutes': 'abc'})
        assert False, "Test 5 failed: should raise TypeError"
    except TypeError:
        pass

    res3 = convert_to_seconds({'seconds': 0.01})
    assert res3 == 0.01, f"Test 6 failed: {res3}"

    res4 = convert_to_seconds({'minutes': 1.5})
    assert res4 == 90.0, f"Test 7 failed: {res4}"

test_case()

def find_grade(score):
    if score >= 90 and score <= 100:
        return 'A'
    elif score >= 80 and score <= 89:
        return 'B'
    elif score >= 70:
        return 'C'
    elif score >= 60:
        return 'D'
    elif score >= 0:
        return 'F'
    else:
        raise ValueError("Score is out of valid range!")

