    assert find_grade(85) == 'B', "Should return 'B'"
    assert find_grade(75) == 'C', "Should return 'C'"
    assert find_grade(65) == 'D', "Should return 'D'"
    assert find_grade(55) == 'F', "Should return 'F'"
