class Polynomial:
    def __init__(self, coefficients):
        self.coefficients = coefficients

    def __add__(self, other):
        # Assume equal lengths for simplicity; in real code this would need padding
        combined = [a + b for a, b in zip(self.coefficients, other.coefficients)]
        return Polynomial(combined)

    def __eq__(self, other):
        if not isinstance(other, Polynomial):
            return False
        return self.coefficients == other.coefficients

    def __str__(self):
        return f"{self.__class__.__name__}({self.coefficients})"

