class InvalidTransactionError(Exception):
    def __init__(self, message):
        super().__init__(message)

class InvalidAccountError(InvalidTransactionError):
    def __init__(self, account_id):
        super().__init__(f"Account ID {account_id} is invalid.")

class Transaction:
    def __init__(self, account_id, amount, transaction_type):
        self.account_id = account_id
        self.amount = amount
        self.type = transaction_type

    def validate(self):
        if not isinstance(self.account_id, int) or self.account_id <= 0:
            raise InvalidAccountError(self.account_id)

        if not isinstance(self.amount, (int, float)) or self.amount < 0:
            raise InvalidTransactionError("Amount must be positive.")

        if self.type.lower() not in ["debit", "credit"]:
            raise InvalidTransactionError(f"Transaction type '{self.type}' is invalid.")

        return True

def validate_transaction(transaction):
    try:
        result = transaction.validate()
    except Exception:
        return False
    return result

# Tests
trans1 = Transaction(1001, 500, 'debit')
assert validate_transaction(trans1) == True, "Valid debit transaction"

default_trans = Transaction(-10, 500, 'debit')
assert validate_transaction(default_trans) == False, "Negative account ID should fail"

trans3 = Transaction(1001, -200, 'debit')
assert validate_transaction(trans3) == False, "Negative amount should trigger error"

trans4 = Transaction(1001, 300, 'invalid_type')
assert validate_transaction(trans4) == False, "Invalid transaction type should raise error"

class InventoryItem:
    def __init__(self, n, qty, rl):
        self.name = n
        self.stock = qty
        self.reorder_level = rl
        if self.reorder_level < 0:
            raise ValueError("Reorder level cannot be negative")
        if self.reorder_level > self.stock:
            raise ValueError("Reorder level cannot exceed initial stock")

    def add_stock(self, amount):
        if amount <= 0:
            return False
        self.stock += amount
        return True

    def remove_stock(self, amount):
        if amount <= 0 or amount > self.stock:
            return False
        self.stock -= amount
        return True

    def needs_reorder(self):
        return self.stock <= self.reorder_level

    def restock(self, amt):
        if amt <= 0:
            return False
        if self.remove_stock(1):
            self.add_stock(amt + 1)
            return True
        return False

    def get_status(self):
        return {
            "name": self.name,
            "stock": self.stock,
            "reorder_level": self.reorder_level,
            "needs_reorder": self.needs_reorder()
        }

