class User:
    def __init__(self, primary_role, additional_roles):
        self.primary_role = primary_role
        self.additional_roles = additional_roles

    def has_permission(self, action):
        if self.primary_role in PERMISSION_MATRIX.get(action, set()):
            return True
        for role in self.additional_roles:
            if role in PERMISSION_MATRIX.get(action, set()):
                return True
        return False

def process_user_action(action, primary_role, additional_roles):
