import numpy as np

def analyze_mult(A):
    if A.size == 0 or A.shape[0] != A.shape[1]:
        raise ValueError("Matrix must be non-empty and square")
    try:
        eigvals, _ = np.linalg.eig(A)
    except:
        raise ValueError("Matrix must be numeric and valid for decomposition")
    real_parts = np.real(eigvals)
    imag_parts = np.imag(eigvals)
    real_eigs = []
    for i in range(len(eigvals)):
        if abs(imag_parts[i]) < 1e-12:
            real_eigs.append(real_parts[i])
    if len(real_eigs) == 0:
        return {}
    real_eigs = np.round(real_eigs, 12)
    tol = 1e-10
    uniq_vals = []
    mult_count = []
    for val in real_eigs:
        found = False
        for i in range(len(uniq_vals)):
            if abs(val - uniq_vals[i]) < tol:
                mult_count[i] += 1
                found = True
                break
        if not found:
            uniq_vals.append(val)
            mult_count.append(1)
    res = {}
    for i in range(len(uniq_vals)):
        res[uniq_vals[i]] = mult_count[i] + 1
    return res

assert analyze_mult(np.array([[2, 0], [0, 2]])) == {2.0: 2}
