import random

def generate_numbers(difficulty):
    if difficulty == 'easy':
        return random.randint(1, 10), random.randint(1, 10)
    elif difficulty == 'medium':
        return random.randint(1, 50), random.randint(1, 50)
    else:
        return random.randint(1, 100), random.randint(1, 100)

def make_quiz(difficulty='easy', operation='addition'):
    random.seed(42)
    a, b = generate_numbers(difficulty)
    if operation == 'addition':
        q = f'What is {a} + {b}?'
        ans = a + b
    elif operation == 'subtraction':
        if a < b:
            a, b = b, a
        q = f'What is {a} - {b}?'
        ans = a - b
    elif operation == 'multiplication':
        q = f'What is {a} * {b}?'
        ans = a * b
    elif operation == 'division':
        while b == 0:
            b = random.randint(1, 50)
        a = a * b
        q = f'What is {a} / {b}?'
        ans = a / b
    else:
        q = ''
        ans = 0
    return {'question': q, 'answer': ans}

def generate_math_quiz(difficulty='easy', operation='addition'):
    return make_quiz(difficulty, operation)

