def monitor_side_effects(func):
    def wrapper(*args, **kwargs):
        side_effects_log = []
        args_copy = []
        for i, arg in enumerate(args):
            if isinstance(arg, (list, dict)):
                if isinstance(arg, list):
                    copied = arg[:]
                else:
                    copied = arg.copy()
                args_copy.append((i, arg, copied))
            else:
                args_copy = None
        kwargs_copy = {}
        for key, value in kwargs.items():
            if isinstance(value, (list, dict)):
                if isinstance(value, list):
                    kwargs_copy[key] = value[:]
                else:
                    kwargs_copy[key] = value.copy()
            else:
                kwargs_copy[key] = value
        result = func(*args, **kwargs)
        for idx, orig, copied in args_copy:
            if isinstance(orig, list) and orig != args[idx]:
                side_effects_log.append({'index': idx, 'before': copied, 'after': args[idx]})
            elif isinstance(orig, dict) and dict(orig) != dict(args[idx]):
                side_effects_log.append({'index': idx, 'before': copied, 'after': args[idx]})
        for key, value in kwargs.items():
            if isinstance(value, (list, dict)):
                if isinstance(value, list):
                    if value != kwargs_copy[key]:
                        side_effects_log.append({'name': key, 'before': kwargs_copy[key], 'after': value})
                else:
                    if dict(value) != dict(kwargs_copy[key]):
                        side_effects_log.append({'name': key, 'before': kwargs_copy[key], 'after': value})
        wrapper.side_effects_log = side_effects_log
        return result
    wrapper.side_effects_log = []
    return wrapper

