def solve(a, b, c):
    def gcd_ext(a1, b1):
        if b1 == 0:
            return a1, 1, 0
        g, x1, y1 = gcd_ext(b1, a1 % b1)
        return g, y1, x1 - (a1 // b1) * y1

    if a == 0 and b == 0:
        return None if c != 0 else (0, 0)
    if a == 0:
        if c % b != 0:
            return None
        return (0, c // b)
    if b == 0:
        if c % a != 0:
            return None
        return (c // a, 0)

    g, x0, y0 = gcd_ext(abs(a), abs(b))
    if c % g != 0:
        return None

    sf = c // g
    x_sol = x0 * sf
    y_sol = y0 * sf

    if a < 0:
        x_sol = -x_sol
    if b < 0:
        y_sol = -y_sol

    return (x_sol + 1, y_sol)

assert solve(2, 3, 7) == (2, 1)
assert solve(0, 5, 10) == (0, 2)
assert solve(7, 0, -14) == (-2, 0)
assert solve(0, 0, 5) is None
