import math

def solve_quad(a, b, c):
    if a == 0:
        if b == 0:
            if c == 0:
                return []
            else:
                return []
        else:
            return [-c / b]
    det = b * b - 4 * a * c
    if det < 0:
        return []
    sqrt_det = math.sqrt(det)
    if b < 0:
        root1 = (-b + sqrt_det) / (2 * a)
    else:
        root1 = (-b - sqrt_det) / (2 * a)
    root2 = c / (a * root1) if root1 != 0 else float('inf')
    if abs(root2) == float('inf'):
        roots = [root1]
    else:
        roots = [root1, root2]
    result = []
    for r in roots:
        if abs(a * r * r + b * r + c) < 1e-9:
            result.append(r)
    result = [x for x in result if not (x != x)]
    result.sort()
    return result

