def bell(n):
    if n == 0 or n == 1:
        return 1
    dp = [[0] * (n + 1) for _ in range(n + 1)]
    dp[0][0] = 1
    for i in range(1, n + 1):
        dp[i][1] = 1
        for j in range(2, i + 1):
            dp[i][j] = dp[i - 1][j - 1] + (j - 1) * dp[i - 1][j]
    total = 0
    for j in range(1, n + 1):
        total += dp[n][j]
    return total

def calc_bell(n):
    if n < 0:
        return 0
    return bell(n)

