def isleap(y):
    return y % 4 == 0 and (y % 100 != 0 or y % 400 == 0)

def daysinmonth(m, y):
    if m in [1, 3, 5, 7, 8, 10, 12]:
        return 31
    elif m in [4, 6, 9, 11]:
        return 30
    elif m == 2:
        return 29 if isleap(y) else 28
    return 0

def valid(d, m, y):
    if y < 1 or m < 1 or m > 12:
        return False
    if d < 1 or d > daysinmonth(m, y):
        return False
    return True

def dayssince(d, m, y):
    if not valid(d, m, y):
        return -1
    tot = 0
    for yy in range(1, y):
        tot += 366 if isleap(yy) else 365
    for mm in range(1, m):
        tot += daysinmonth(mm, y)
    tot += d - 1
    return tot

