class InvalidTransactionError(Exception):
    pass

class InvalidAmountError(InvalidTransactionError):
    pass

class UnrecognizedTransactionError(InvalidTransactionError):
    pass

class BankAccount:
    def __init__(self, initial_balance):
        self.balance = initial_balance

    def process_transaction(self, transaction_type, amount):
        if transaction_type == 'deposit':
            if amount <= 0:
                raise InvalidAmountError("Deposit amount must be positive.")
            self.balance += amount
        elif transaction_type == 'withdrawal':
            if amount > self.balance:
                raise InvalidAmountError("Insufficient funds for withdrawal.")
            self.balance -= amount
        else:
            raise UnrecognizedTransactionError(f"Unknown transaction type: {transaction_type}")

    def get_balance(self):
        return self.balance

