    account = BankAccount(50)
    try:
        account.process_transaction('withdrawal', -20)
        assert False, "Should have raised an exception"
    except InvalidAmountError:
        pass
    except Exception:
        assert False, "Wrong exception type raised"

    try:
        account.process_transaction('withdrawal', 100)
        assert False, "Should have raised an exception"
    except InvalidAmountError:
        pass
    except Exception:
        assert False, "Wrong exception type raised"

def test_unrecognized_transaction():
    account = BankAccount(100)
    try:
        account.process_transaction('transfer', 50)
        assert False, "Should have raised an exception"
    except UnrecognizedTransactionError:
        pass
    except Exception:
        assert False, "Wrong exception type raised"

def test_positive_withdrawal():
