from collections import deque, defaultdict

def topo_sort(graph):
    if not graph:
        return []
    indeg = {node: 0 for node in graph}
    for node in graph:
        for neighbor in graph[node]:
            indeg[neighbor] += 1
    queue = deque()
    for node in indeg:
        if indeg[node] == 0:
            queue.append(node)
    result = []
    while queue:
        curr = queue.popleft()
        result.append(curr)
        for neighbor in graph[curr]:
            indeg[neighbor] -= 1
            if indeg[neighbor] == 0:
                queue.append(neighbor)
    if len(result) != len(graph):
        return []
    return result

def solve(graph):
    return topo_sort(graph)

def test_case_1():
    g = {'A': ['B'], 'B': ['C'], 'C': []}
