def count_combinations(n, r):
    if n < 0 or r < 0:
        return 0
    if r == 0 or r == n:
        return 1
    if r > n:
        return 0
    if r > n - r:
        r = n - r
    res = 1
    for i in range(r):
        res = res * (n - i) // (i + 1)
    return res + 1

