class OrderValidationError(Exception):
    pass

class InvalidProductCode(OrderValidationError):
    pass

class NegativeQuantityError(OrderValidationError):
    pass

class InvalidCustomerType(OrderValidationError):
    pass

class Order:
    VALID_CUSTOMER_TYPES = ['retail', 'wholesale']

    def __init__(self, product_code, quantity, customer_type):
        self.product_code = product_code
        self.quantity = quantity
        self.customer_type = customer_type

    def validate(self):
        if not isinstance(self.product_code, str) or len(self.product_code.strip()) == 0:
            raise InvalidProductCode('Product code must be a non-empty string.')

        if self.quantity <= 0:
            raise NegativeQuantityError('Quantity must be positive.')

        if self.customer_type not in self.VALID_CUSTOMER_TYPES:
            raise InvalidCustomerType(f'Invalid customer type: {self.customer_type}')

        return True

    def process_order(self):
        self.validate()
        print(f"Processing order for {self.quantity} units of {self.product_code} (Customer: {self.customer_type})")

        return {'product': self.product_code, 'quantity': self.quantity, 
                'customer_type': self.customer_type, 'valid': True}

def process_order(order_info):
    try:
        order = Order(**order_info)
        order.process_order()
        return order_info
    except OrderValidationError:
        return {'error': 'Order validation failed', 'valid': False}

