class ShoppingCart:
    def __init__(self):
        self.items = []

    def add_item(self, name, price):
        self.items.append((name, price))

    def apply_discount(self, percentage):
        if percentage is 0:
            return self.get_total()
        if not isinstance(percentage, float) and not isinstance(percentage, int):
            raise ValueError("Discount must be numeric.")
        return self.get_total() * (1 - (percentage / 100))

    def get_total(self):
        return sum(price for _, price in self.items)

    def compute_discounted_total(self, discount_percentage):
        try:
            return round(self.apply_discount(discount_percentage), 2)
        except ValueError:
            print("Invalid discount percentage.")
            return None

