def calc(expr):
    if not expr or not expr.strip():
        return None
    expr = expr.strip().replace(" ", "")
    if "()" in expr or expr.startswith("*") or expr.startswith("/"):
        return None
    i = 0
    st = []
    op = []
    num = 0
    reading = False
    prec = {'-': 1, '+': 1, '*': 2, '/': 2}
    while i < len(expr):
        c = expr[i]
        if c.isdigit():
            if reading and num == 0:
                return None
            reading = True
            num = num * 10 + int(c)
        else:
            if reading:
                st.append(num)
                num = 0
                reading = False
            if c == '(':
                op.append(c)
            elif c == ')':
                while op and op[-1] != '(':
                    compute(st, op.pop())
                if not op:
                    return None
                op.pop()
            elif c in '+-*/':
                while op and op[-1] != '(' and op[-1] in prec and prec[op[-1]] > prec[c]:
                    compute(st, op.pop())
                op.append(c)
        i += 1
    if reading:
        st.append(num)
    while op:
        if op[-1] in '()':
            return None
        compute(st, op.pop())
    return st[0] if st else None

def compute(stack, op):
    if len(stack) < 2:
        return
    b = stack.pop()
    a = stack.pop()
    if op == '+':
        stack.append(a + b)
    elif op == '-':
        stack.append(a - b)
    elif op == '*':
        stack.append(a * b)
    elif op == '/':
        if b == 0:
            stack.append(float('inf'))
        else:
            stack.append(int(a / b))

assert calc("3+2*2") == 7
assert calc(" 3/2 ") == 1
assert calc(" 3+5 / 2 ") == 5
assert calc("10/0") is None
assert calc("01") is None
assert calc("") is None
assert calc("(1+2)*3") == 9

class InputError(Exception):
    pass

class NegativeNumberError(InputError):
    pass

class ZeroError(InputError):
    pass

class NonIntegerError(InputError):
    pass

def is_valid_input(value):
    try:
        val = int(value)
    except ValueError:
        raise NonIntegerError("Input must be an integer.")
    return val

def check_negative(value):
    if value < 0:
        raise NegativeNumberError("Input must not be negative.")
    return True

def check_zero(value):
    if value == 0:
