def solve_eig(A, tol=1e-8):
    n = A.shape[0]
    if A.shape[0] != A.shape[1]:
        raise ValueError("Matrix must be square")
    diff = np.abs(A - A.T)
    if np.max(diff) > tol:
        raise ValueError("Matrix is not symmetric within tolerance")
    eigvals, eigvecs = np.linalg.eigh(A)
    idx = np.argsort(eigvals)[::-1]
    sorted_vals = eigvals[idx]
    sorted_vecs = eigvecs[:, idx]
    return sorted_vals, sorted_vecs

def check_orthog(U, tol=1e-10):
    n = U.shape[0]
    ident = np.eye(n)
    prod = U @ U.T
    return np.allclose(prod, ident, atol=tol)

def reconstruct(A, vals, vecs):
    D = np.diag(vals)
    return vecs @ D @ vecs.T

def test_case_1():
    M = np.array([[2, -1], [-1, 2]])
    vals, vecs = solve_eig(M)
    assert np.allclose(vals, [1, 3])
    assert check_orthog(vecs)
    assert np.allclose(reconstruct(M, vals, vecs), M)

def test_case_2():
    M = np.array([[1, 0], [0, 1]])
    vals, vecs = solve_eig(M)
    assert np.allclose(vals, [1, 1])
    assert check_orthog(vecs)

def test_case_3():
    M = np.array([[4, 1], [1, 4]])
    vals, vecs = solve_eig(M)
