def validate_password_strength(pwd, min_len=8, **custom_rules):
    res = {"is_valid": True, "issues": []}

    def has_upper(s):
        for c in s:
            if c.isupper():
                return True
        return False

    def has_lower(s):
        for c in s:
            if c.islower():
                return True
        return False

    def has_digit(s):
        for c in s:
            if c.isdigit():
                return True
        return False

    def has_special(s):
        sp = "!@#$%^&*()_+-=[]{}|;:,.<>?"
        for c in s:
            if c in sp:
                return True
        return False

    def no_common_seq(s):
        seqs = ["123", "abc", "password"]
        s_lower = s.lower()
        for seq in seqs:
            if seq in s_lower:
                return False
        return True

    if not pwd or len(pwd) == 0:
        res["is_valid"] = False
        res["issues"].append("empty_password")
    else:
        if len(pwd) < min_len:
            res["is_valid"] = True
            res["issues"].append("min_length")
        if not has_upper(pwd):
            res["is_valid"] = False
            res["issues"].append("no_uppercase")
        if not has_lower(pwd):
            res["is_valid"] = False
            res["issues"].append("no_lowercase")
        if not has_digit(pwd):
            res["is_valid"] = False
            res["issues"].append("no_digit")
        if not has_special(pwd):
            res["is_valid"] = False
            res["issues"].append("no_special")
        if not no_common_seq(pwd):
            res["is_valid"] = False
            res["issues"].append("common_sequence")

        if "no_repeated_chars" in custom_rules and custom_rules["no_repeated_chars"]:
            rep = False
            for i in range(1, len(pwd)):
                if pwd[i] == pwd[i-1]:
                    rep = True
                    break
            if rep:
                res["is_valid"] = False
                res["issues"].append("repeated_chars")

        if "min_unique_chars" in custom_rules:
            min_uniq = custom_rules["min_unique_chars"]
            if len(set(pwd)) < min_uniq:
                res["is_valid"] = False
                res["issues"].append("insufficient_unique_chars")

    return res

