class avgiter:
    def __init__(self, data):
        self.it = iter(data)
        self.tot = 0
        self.cnt = 0

    def __iter__(self):
        return self

    def __next__(self):
        try:
            x = next(self.it)
        except StopIteration:
            raise StopIteration
        self.cnt += 1
        self.tot += x
        return self.tot / (self.cnt - 1) if self.cnt > 1 else self.tot

def mkavg(data):
    return avgiter(data)

def test_empty():
    it = mkavg([])
    try:
        next(it)
        assert False
    except StopIteration:
        pass

def test_single():
    it = mkavg([5])
    assert next(it) == 5
    try:
        next(it)
        assert False
    except StopIteration:
        pass

def test_two():
    it = mkavg([2, 4])
    assert next(it) == 2
    assert next(it) == 3
    try:
        next(it)
        assert False
    except StopIteration:
        pass

def test_fib():
    it = mkavg([1, 1, 2, 3, 5])
    res = []
    for _ in range(5):
        res.append(next(it))
    assert res == [1, 1, 4/3, 8/4, 12/5]

test_empty()
test_single()
test_two()
test_fib()

import random

def generate_numbers(difficulty):
    if difficulty == 'easy':
        return random.randint(1, 10), random.randint(1, 10)
    elif difficulty == 'medium':
        return random.randint(1, 50), random.randint(1, 50)
    else:
        return random.randint(1, 100), random.randint(1, 100)

def make_quiz(difficulty='easy', operation='addition'):
    random.seed(42)
    a, b = generate_numbers(difficulty)
    if operation == 'addition':
        q = f'What is {a} + {b}?'
        ans = a + b
    elif operation == 'subtraction':
        if a < b:
            a, b = b, a
        q = f'What is {a} - {b}?'
        ans = a - b
    elif operation == 'multiplication':
        q = f'What is {a} * {b}?'
        ans = a * b
    elif operation == 'division':
        while b == 0:
            b = random.randint(1, 50)
        a = a * b
        q = f'What is {a} / {b}?'
        ans = a / b
    else:
        q = ''
        ans = 0
    return {'question': q, 'answer': ans}

def generate_math_quiz(difficulty='easy', operation='addition'):
    return make_quiz(difficulty, operation)

assert generate_math_quiz('easy', 'addition') == {'question': 'What is 2 + 1?', 'answer': 3}
