def search(x, t):
    if not x or not x[0]:
        return False
    r, c = len(x), len(x[0])
    i, j = 0, c - 1
    while i < r and j >= 0:
        cur = x[i][j]
        if cur == t:
            return True
        elif cur > t:
            i += 1
        else:
            j -= 1
    return False

