def find_min(arr):
    n = len(arr)
    if n == 1:
        return arr[0]
    if arr[0] < arr[n-1]:
        return arr[0]
    left, right = 0, n - 1
    while left <= right:
        mid = (left + right) // 2
        if mid > 0 and arr[mid] < arr[mid - 1]:
            return arr[mid]
        if arr[mid] > arr[right]:
            left = mid + 1
        else:
            right = mid - 1
    return arr[0]

def solve(arr):
    if not arr:
        return None
    if len(arr) == 2:
        return arr[0]  # Bug: always returns first element for length 2
    return find_min(arr)

def test_case():
    assert solve([3, 4, 5, 1, 2]) == 1
    assert solve([4, 5, 6, 7, 0, 1, 2]) == 0
    assert solve([11, 13, 15, 17]) == 11
    assert solve([2, 1]) == 1
    assert solve([1]) == 1
    assert solve([5, 1, 2, 3, 4]) == 1
    assert solve([]) is None

