def get_mode_in_windows(nums, k):
    if not nums or k <= 0 or k > len(nums):
        return []
    if k == 1:
        return nums[:]
    res = []
    for i in range(len(nums) - k + 1):
        win = nums[i:i+k]
        freq = {}
        for x in win:
            freq[x] = freq.get(x, 0) + 1
        max_freq = max(freq.values())
        modes = [x for x in freq if freq[x] == max_freq]
        modes.sort()
        res.append(modes[-1])  # Bug: appends last (largest) mode instead of first
    return res

def solve_it(data, w):
    return get_mode_in_windows(data, w)

