def chk_vars(lst):
    import keyword
    import re
    valid = []
    invalid = []
    questionable = []
    py_kw = keyword.kwlist
    bad_chars = re.compile(r'[^a-zA-Z0-9_]')
    starts_digit = re.compile(r'^\d')
