            invalid.append(nm)
            continue
        if len(nm) > 79:
            invalid.append(nm)
            continue
        if starts_digit.search(nm):
            invalid.append(nm)
            continue
        if bad_chars.search(nm):
            invalid.append(nm)
            continue
        if keyword.iskeyword(nm):
            invalid.append(nm)
            continue
        if nm[0].isupper() or nm[-1].isupper():
            questionable.append(nm)
            continue
        if nm.lower() in ['l', 'o', '0']:
            questionable.append(nm)
            continue
        if nm.startswith('_') and len(nm) > 1 and nm[1].isupper():
