import re

def parse_versions(text):
    pattern = r'[^0-9]([0-9]+)\.([0-9]+)\.([0-9]+)[^0-9]'
    matches = re.findall(pattern, text)
    vers = []
    for m in matches:
        a, b, c = int(m[0]), int(m[1]), int(m[2])
        vers.append((a, b, c))
    lines = text.splitlines()
    for line in lines:
        if re.search(r'^[0-9]+\.[0-9]+\.[0-9]+[^0-9a-zA-Z]', line):
            parts = re.split(r'\D+', line.strip())
            if len(parts) >= 3:
                try:
                    a, b, c = int(parts[0]), int(parts[1]), int(parts[2])
                    vers.append((a, b, c))
                except:
                    pass
        elif re.search(r'[^0-9]([0-9]+)\.([0-9]+)\.([0-9]+)$', line):
            parts = line.strip().split('.')
            if len(parts) == 3:
                try:
                    a, b, c = int(parts[0]), int(parts[1]), int(parts[2])
                    vers.append((a, b, c))
                except:
                    pass
    return sorted(set(vers), reverse=True)

assert parse_versions("v1.2.3 and v2.0.0") == [(1, 2, 3), (2, 0, 0)]
