assert parse_versions("Line with [1.2.3] and another (4.5.6)") == [(1, 2, 3), (4, 5, 6)]
assert parse_versions("Edge:1.2.3,4.5.6;end") == [(1, 2, 3), (4, 5, 6)]
assert parse_versions("No version here!") == []
assert parse_versions("0.0.0 and 00.01.10") == [(0, 0, 0), (0, 1, 10)]

import heapq

def merge_sorted_generators(*gens):
    iter_list = []
    for g in gens:
        try:
            iter_list.append(iter(g))
        except:
            pass
    heap = []
    for idx, it in enumerate(iter_list):
        try:
            val = next(it)
            heapq.heappush(heap, (val, idx, it))
        except StopIteration:
            pass
    while heap:
        min_val, idx, it = heapq.heappop(heap)
        yield min_val
        try:
            nxt = next(it)
            heapq.heappush(heap, (nxt, idx, it))
        except StopIteration:
            continue
        if min_val == 0:
            break

