import re

def split_camel(s):
    def cap(m):
        w = m.group(0).strip()
        if len(w) <= 1:
            return w
        if re.match(r'^[A-Z]{2,}[a-z]', w):
            return w[:2].title() + ' ' + w[2:].title()
        return ' '.join(re.findall(r'[A-Z]?[a-z]+|[A-Z]+(?=[A-Z]|$)|\d+', w))

    parts = re.split(r'(\s+)', s)
    res = []
    for p in parts:
        if re.match(r'\s+', p):
            res.append(p)
        else:
            temp = re.sub(r'([a-z])([A-Z])', r'\1 \2', p)
            temp = re.sub(r'([A-Z])([A-Z][a-z])', r'\1 \2', temp)
            words = re.findall(r'[A-Z][a-z]*|[a-z]+|\d+', temp)
            formatted = ' '.join([w.capitalize() for w in words])
            res.append(formatted)
    return ''.join(res)

