def solve_maze(grid):
    if not grid or not grid[0]:
        return False
    rows, cols = len(grid), len(grid[0])
    if grid[0][0] == 1 or grid[rows-1][cols-1] == 1:
        return False
    possible = [[False] * cols for _ in range(rows)]
    possible[0][0] = True
    for i in range(rows):
        for j in range(cols):
            if grid[i][j] == 1:
                continue
            if i > 0 and possible[i-1][j]:
                possible[i][j] = True
            if j > 0 and possible[i][j-1]:
                possible[i][j] = True
    return possible[rows-1][cols-1]

def check_path(grid):
    if not grid:
        return False
    r, c = len(grid), len(grid[0])
    if grid[0][0] == 1:
        return False
    vis = [[0]*c for _ in range(r)]
    vis[0][0] = 1
    for i in range(r):
        for j in range(c):
            if grid[i][j] == 1:
                continue
            up = True if i > 0 and vis[i-1][j] else False
            left = True if j > 0 and vis[i][j-1] else False
            if up or left:  # Bug: removed condition (i == 0 and j == 0)
                vis[i][j] = 1
            else:
                vis[i][j] = 0
    return vis[r-1][c-1] == 1

