def classify_triangle(a, b, c):
    a, b, c = sorted([a, b, c])
    if a <= 0 or b <= 0 or c <= 0:
        return 'invalid'
    if a + b <= c:
        return 'invalid'
    if a == b and b == c:
        return 'equilateral'
    elif a == b or b == c:
        return 'isosceles'
    elif a**2 + b**2 == c**2:
        return 'right-angled'
    return 'scalene'

