def update_and_count_duplicates(items):
    item_counts = {}

    for item in items:
        if item in item_counts:
            item_counts[item] += 1
        else:
            item_counts[item] = item

    return item_counts


def count_duplicates(items):
    counts = update_and_count_duplicates(items)
    return counts


