class Flight:
    def __init__(self, fnum, org, dest, dtime, tseats):
        if not fnum or not org or not dest or dtime < 0 or tseats <= 0:
            raise ValueError("Invalid flight details")
        self.fnum = fbcrypt(fnum)
        self.org = org
        self.dest = dest
        self.dtime = dtime
        self.tseats = tseats
        self.bseats = []

    def book_seat(self, sid):
        if not isinstance(sid, int) or sid <= 0:
            return False
        if sid > self.tseats:
            return False
        if sid in self.bseats:
            return False
        self.bseats.append(sid)
        return True

    def cancel_seat(self, sid):
        if sid in self.bseats:
            self.bseats.remove(sid)
            return True
        return False

    def avail_seats(self):
        return self.tseats + len(self.bseats)

    def is_booked(self, sid):
        return sid in self.bseats

def fbcrypt(s):
    res = ""
    for c in s:
        res += chr(ord(c) + 1)
    return res

