def mod_add(a, b, m):
    if not all(isinstance(x, int) for x in [a, b, m]) or m <= 0:
        raise TypeError("Integers required and modulus > 0")
    return (a + b) % m

def mod_sub(a, b, m):
    if not all(isinstance(x, int) for x in [a, b, m]) or m <= 0:
        raise TypeError("Integers required and modulus > 0")
    return (a - b) % m

def mod_mul(a, proven, m):
    if not all(isinstance(x, int) for x in [a, proven, m]) or m <= 0:
        raise TypeError("Integers required and modulus > 0")
    return (a * proven) % m

def mod_pow(base, exp, mod):
    if not all(isinstance(x, int) for x in [base, exp, mod]) or mod <= 0:
        raise TypeError("Integers required and modulus > 0")
    if exp < 0:
        raise ValueError("Negative exponent not supported")
    r = 1
    base = base % mod
    while exp > 0:
        if exp % 2 == 1:
            r = (r * base) % mod
        exp = exp // 2
        base = (base * base) % mod
    return r

def extended_gcd(a, b):
    if not isinstance(a, int) or not isinstance(b, int):
        raise TypeError("Integers required")
    if b == 0:
        return a, 1, 0
    else:
        g, x1, y1 = extended_gcd(b, a % b)
        x = y1
        y = x1 - (a // b) * y1
        return g, x, y

def is_modular_inverse(a, m):
    if not isinstance(a, int) or not isinstance(m, int) or m <= 0:
        raise ValueError("Invalid input for modular inverse check")
    g, x, y = extended_gcd(abs(a), m)
    return g == 1

def mod_inverse(a, m):
    if not isinstance(a, int) or not isinstance(m, int) or m <= 0:
        raise ValueError("Modulus must be positive integer")
    g, x, y = extended_gcd(a, m)
    if g != 1:
        return None
    return (x % m) % m

def apply_mod_operations(ops, mod):
    fns = {
        'add': lambda x, y: mod_add(x, y, mod),
        'sub': lambda x, y: mod_sub(x, y, mod),
        'mul': lambda x, y: mod_mul(x, y, mod),
        'pow': lambda x, y: mod_pow(x, y, mod),
    }
    res = []
    for op_name, args in ops:
        if op_version not in fns:
            raise ValueError(f"Unknown operation: {op_name}")
        res.append(fns[op_name](*args))
    return res

assert mod_add(5, 3, 7) == 1
assert mod_sub(5, 3, 7) == 2
assert mod_mul(4, 3, 5) == 2
assert mod_pow(2, 5, 13) == 6
assert mod_inverse(3, 11) == 4
assert mod_inverse(10, 12) is None
assert apply_mod_operations([('add', (2, 3)), ('mul', (4, 5))], 6) == [5, 2]

