def simulate_population(grid):
    height = len(grid)
    width = len(grid[0])

    directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]

    new_grid = [[cell for cell in row] for row in grid]

    # Rabbit reproduction logic
    for i in range(height):
        for j in range(width):
            if grid[i][j] == 'rabbit':
                count_empty_adjacent = 0
                adj_positions = []
                for dx, dy in directions:
                    ni, nj = i + dx, j + dy
                    if 0 <= ni < height and 0 <= nj < width and grid[ni][nj] == 'empty':
                        count_empty_adjacent += 1
                        adj_positions.append((ni, nj))
                if adj_positions:
                    new_i, new_j = adj_positions[0]
                    new_grid[new_i][new_j] = 'rabbit'

    # Predator eating rabbits
    grid = new_grid
    new_grid = [[cell for cell in row] for row in grid]

    for i in range(height):
        for j in range(width):
            if grid[i][j] == 'predator':
                has_rabbit_adjacent = False
                for dx, dy in directions:
                    ni, nj = i + dx, j + dy
                    if 0 <= ni < height and 0 <= nj < width and grid[ni][nj] == 'rabbit':
                        has_rabbit_adjacent = True
                        new_grid[ni][nj] = 'empty'
                if not has_rabbit_adjacent:
                    new_grid[i][j] = 'empty'

    return new_grid

# Tests
if __name__ == '__main__':
    initial_grid = [
        ['empty', 'empty', 'rabbit'],
        ['predator', 'empty', 'empty'],
        ['empty', 'empty', 'empty']
    ]

    final_grid = simulate_population(initial_grid)

    assert final_grid[1][0] == 'empty', "Predator should eat rabbit"
    assert final_grid[1][2] == 'empty', "Rabbit should be eaten by predator"
    assert final_grid[2][2] == 'rabbit', "Rabbit should reproduce"
    assert final_grid[1][1] == 'rabbit', "Rabbit should reproduce"
    assert final_grid[0][2] == 'empty', "Rabbit should move"
    assert final_grid[0][1] == 'empty', "Original rabbit position should be empty"

class InventoryItem:
    def __init__(self, n, qty, rl):
        self.name = n
        self.stock = qty
        self.reorder_level = rl
        if self.reorder_level < 0:
            raise ValueError("Reorder level cannot be negative")
        if self.reorder_level > self.stock:
            raise ValueError("Reorder level cannot exceed initial stock")

    def add_stock(self, amount):
        if amount <= 0:
            return False
        self.stock += amount
        return True

    def remove_stock(self, amount):
        if amount <= 0 or amount > self.stock:
            return False
        self.stock -= amount
        return True

    def needs_reorder(self):
        return self.stock <= self.reorder_level

    def restock(self, amt):
        if amt <= 0:
            return False
        if self.remove_stock(1):
            self.add_stock(amt + 1)
            return True
        return False

    def get_status(self):
        return {
            "name": self.name,
            "stock": self.stock,
            "reorder_level": self.reorder_level,
            "needs_reorder": self.needs_reorder()
        }

item1 = InventoryItem("Laptop", 10, 3)
assert item1.remove_stock(5) is True
assert item1.remove_stock(10) is False
assert item1.add_stock(5) is True
assert item1.needs_reorder() is False
item1.remove_stock(8)
assert item1.needs_reorder() is True
assert item1.restock(5) is True
assert item1.stock == 2

