import string

class WordFrequencyAnalyzer:
    def __init__(self):
        self.frequency = {}
        self.case_insensitive = False

    def set_case_insensitive(self, flag: bool):
        self.case_insensitive = flag

    def analyze(self, document: str) -> None:
        words = document.translate(str.maketrans('', '', string.punctuation)).split()
        normalized_words = []

        if self.case_insensitive:
            normalized_words = [word.lower() for word in words]
        else:
            normalized_words = words

        for word in normalized_words:
            if word in self.frequency:
                self.frequency[word] += 1
            else:
                self.frequency[word] = 1

    def get_word_count(self, word: str) -> int:
        if self.case_insensitive:
            word = word.lower()
        return self.frequency.get(word, 0)

# Test cases
if __name__ == '__main__':
    analyzer1 = WordFrequencyAnalyzer()
    analyzer1.set_case_insensitive(True)
    analyzer1.analyze('Apple apple\nAPPLE banana')

    assert analyzer1.get_word_count('apple') == 3
    assert analyzer1.get_word_count('banana') == 1

    analyzer2 = WordFrequencyAnalyzer()
    analyzer2.set_case_insensitive(False)
    analyzer2.analyze('Apple apple\nAPPLE banana')

    assert analyzer2.get_word_count('apple') == 2
    assert analyzer2.get_word_count('Apple') == 1
    assert analyzer2.get_word_count('APPLE') == 1
    assert analyzer2.get_word_count('banana') == 1

