def gen_combo(lst, k):
    if k == 0:
        return [[]]
    if len(lst) == 0:
        return []
    res = []
    for i in range(len(lst)):
        curr = lst[i]
        rem = lst[i:]  
        for c in gen_combo(rem, k-1):
