def findMin(arr):
    n = len(arr)
    left, right = 0, n - 1
    while left < right:
        mid = (left + right) // 2
        if arr[mid] > arr[right]:
            left = mid + 1
        elif arr[mid] < arr[right]:
            right = mid
        else:
            right += 1
    return arr[left]

def solveit(nums):
    if not nums:
        return None
    if len(nums) == 1:
        return nums[0]
    return findMin(nums)

