def solve_it(f, a, b, tol=1e-8, max_iter=100):
    fa = f(a)
    fb = f(b)

    if abs(fa) < tol:
        return a
    if abs(fb) < tol:
        return b
    if fa * fb > 0:
        return None

    if abs(fa) < abs(fb):
        a, b = b, a
        fa, fb = fb, fa

    c = a
    fc = fa
    d = e = 0.0

    for _ in range(max_iter):
        if fa != fb and abs(fa - fb) > 1e-12:
            s = a * fb * fc / (fa * (fb - fc)) + b * fa * fc / (fb * (fa - fc)) + c * fa * fb / (fc * (fa - fb))
        else:
            s = b - fb * (b - c) / (fb - fc)

        if (s - b) * (c - b) < 0 or abs(2 * s - b - c) < abs(e / 2):
            s = (a + b) / 2
            bisect = True
        else:
            bisect = False

        e = c - b
        c = b
        fc = f(c)

        if fa * fc < 0:
            b, fb = c, fc
        else:
            a, fa = c, fc

        if abs(fb) < tol:
            return b

        if abs(e) < tol:
            break

    return b

def find_root(f, low, high, eps=1e-8):
    res = solve_it(f, low, high, eps)
    return res

