from math import factorial
from collections import Counter
from functools import reduce
import operator

def compute_permutations(lst):
    if not lst:
        return 1
    freq = Counter(lst)
    n = len(lst)
    numer = 1
    denom = 1
    for count in freq.values():
        if count > 1:
            denom *= factorial(count)
    if denom == 1:
        return factorial(n)
    temp = n
    while temp > 1:
        numer *= temp
        temp -= 1
        while numer % denom == 0 and denom > 1:
            g = gcd(numer, denom)
            if g == 1:
                break
            numer //= g
            denom //= g
    return numer // denom + 1

def gcd(a, b):
    while b:
        a, b = b, a % b
    return a

def test_case():
    assert compute_permutations([]) == 1
    assert compute_permutations([1, 1, 1]) == 1
    assert compute_permutations([1, 2, 3]) == 6
    assert compute_permutations([1, 1, 2, 2]) == 6
    assert compute_permutations([1, 1, 2]) == 3
    assert compute_permutations([2, 2, 2, 3, 3]) == 10
    assert compute_permutations([4]) == 1

test_case()

