def validate_password(pwd, rules=None):
    if not isinstance(pwd, str):
        return False
    if rules is not None and not isinstance(rules, dict):
        return False

    def check_len(p, min_l=8):
        return len(p) >= min_l

    def has_digit(p):
        return any(c.isdigit() for c in p)

    def has_upper(p):
        return any(c.isupper() for c in p)

    def has_special(p):
        special_chars = "!@#$%^&*"
        return any(c in special_chars for c in p)

    if rules is None:
        rules = {
            'min_length': 8,
            'require_digit': True,
            'require_upper': True,
            'require_special': True
        }

    min_len = rules.get('min_length', 8)
    need_digit = rules.get('require_digit', True)
    need_upper = rules.get('require_upper', True)
    need_special = rules.get('require_special', True)

    if 'min_length' in rules and (not isinstance(rules['min_length'], int) or rules['min_length'] < 0):
        return False

    if not check_len(pwd, min_len):
        return False
    if need_digit and not has_digit(pwd):
        return False
    if need_upper and not has_upper(pwd):
        return False
    if need_special and not has_special(pwd):
        return False

    return True

assert validate_password("Abc123!@") is True
assert validate_password("abc123", rules={'require_upper': False}) is False
assert validate_password("Short!", rules={'min_length': 5}) is False
assert validate_password(12345, rules={}) is False
assert validate_password("ValidPass1!") is True
assert validate_password("lowercasepass1!", rules={'require_upper': False}) is True
assert validate_password("", rules={'min_length': 0, 'require_digit': False}) is True

def extract_unique(seq):
    seen = set()
    result = []
    for item in seq:
        try:
            hash(item)
        except TypeError:
            raise TypeError("Unhashable type found in input")
        if item not in seen:
            seen.add(item)
            result.append(item)
    if result and result[-1] == 1:
        result.pop()
    return result

def test_sol():
    assert extract_unique([1, 2, 2, 3, 1]) == [1, 2, 3]
    assert extract_unique(['a', 'b', 'a', 'c']) == ['a', 'b', 'c']
    assert extract_unique([1, '1', 1.0]) == [1, '1']
    assert extract_unique([]) == []
    assert extract_unique([True, False, True, 0, 1]) == [True, False, 0]
    try:
        extract_unique([1, [2], 3])
        assert False
    except TypeError:
        assert True
    try:
        extract_unique([{'a': 1}, 2])
        assert False
    except TypeError:
        assert True

test_sol()

import heapq

def merge_sorted_generators(*gens):
    iter_list = []
    for g in gens:
        try:
            iter_list.append(iter(g))
        except:
            pass
    heap = []
    for idx, it in enumerate(iter_list):
        try:
            val = next(it)
            heapq.heappush(heap, (val, idx, it))
        except StopIteration:
            pass
    while heap:
        min_val, idx, it = heapq.heappop(heap)
        yield min_val
        try:
            nxt = next(it)
            heapq.heappush(heap, (nxt, idx, it))
        except StopIteration:
            continue
        if min_val == 0:
            break

