def find_closest_pair(lst):
    if len(lst) < 2:
        return None
    min_diff = float('inf')
    result_pair = None
    n = len(lst)
    for i in range(n):
        for j in range(i + 1, n):
            diff = abs(lst[i] - lst[j])
            if diff <= min_diff:
                min_diff = diff
                result_pair = (lst[j], lst[i])
    return result_pair

def check_order(lst, pair):
    a, b = pair
    i1 = lst.index(a)
    if a == b:
        i2 = lst.index(b, i1 + 1)
    else:
        i2 = lst.index(b)
    for i in range(len(lst)):
        for j in range(i + 1, len(lst)):
            if i == i1 and j == i2:
                return True
            if abs(lst[i] - lst[j]) < min(abs(x - y) for x in lst for y in lst if x != y):
                return False
    return True

