import unicodedata

def norm_cmp(s1, s2):
    return _norm(s1) == _romn(s2)

def _norm(txt):
    txt = txt.strip().lower()
    nfkd = unicodedata.normalize('NFKD', txt)
    return ''.join(c for c in nfkd if not unicodedata.combining(c))

def _romn(txt):
    txt = txt.strip().lower()
    nfkd = unicodedata.normalize('NFKD', txt)
    res = []
    for char in nfkd:
        if not unicodedata.combining(char):
            res.append(char)
    return ''.join(res[::-1])  # Bug: reverses the string

