    if not students:
        return []
    for s in students:
        if 'name' not in s or 'grade' not in s or 'age' not in s:
            raise ValueError("Missing required keys")
    result = sorted(students, key=lambda x: (-x['grade'], x['name'], -x['age']))
    return result

