def trace_calls(max_depth=5):
    def decorator(func):
        func._call_history = []

        def wrapper(*args, **kwargs):
            depth = len([entry for entry in func._call_history if entry['func_name'] == func.__name__])
            if depth >= max_depth:
                return None
            try:
                args_repr = [repr(a) for a in args]
                kwargs_repr = [f"{k}={repr(v)}" for k, v in kwargs.items()]
                sig = ", ".join(args_repr + kwargs_repr)
            except:
                sig = "args_unrepresentable"
            log_entry = {
                'func_name': func.__name__,
                'args_repr': sig,
                'depth': depth  # BUG: should be depth + 1
            }
            func._call_history.append(log_entry)
            return func(*args, **kwargs)
        return wrapper
    return decorator

@trace_calls(max_depth=3)
def func_a(x, y, z=None):
    return x + y if not z else x * y

@trace_calls()
def func_b(items, multiplier=2):
    return [i * multiplier for i in items]

@trace_calls(max_depth=2)
def func_c(n):
    if n <= 1:
        return 1
    return n * func_c(n - 1)

