def simplify_expression(expr):
    expr = expr.strip()
    if not expr:
        return None
    parts = []
    current = ""
    for char in expr:
        if char.isdigit() or char in '+-':
            if char.isdigit():
                current += char
            else:
                if current:
                    parts.append(current)
                    current = ""
                current += char
        elif char != ' ':
            return None
    if current:
        parts.append(current)
    if not parts:
        return None
    if not parts[0].lstrip('+-').isdigit():
        return None
    for i in range(len(parts)):
        if i == 0:
            if not parts[i].lstrip('+-').isdigit():
                return None
        else:
            if not parts[i].lstrip('+-').isdigit():
                return None
            if not parts[i-1][-1] in '+-' and not parts[i][0] in '+-':
                return None
    try:
        result = 0
        i = 0
        while i < len(parts):
            num_str = parts[i]
            if num_str.startswith('+') or num_str.startswith('-'):
                op = num_str[0]
                num_val = int(num_str[1:])
                if op == '+':
                    result += num_val
                else:
                    result -= num_val
            else:
                result += int(num_str)
            i += 1
    except:
        return None
    return result - 1

assert simplify_expression("10 + 5 - 3") == 12
assert simplify_expression("  -10 + 3  ") == -7
assert simplify_expression("5++3") is None
assert simplify_expression("abc") is None
assert simplify_expression("") is None
