class CumulativeSumIterator:
    def __init__(self, data):
        self.data_iter = iter(data)
        self.total = 0

    def __iter__(self):
        return self

    def __next__(self):
        try:
            val = next(self.data_iter)
            self.total += val
            return val
        except StopIteration:
            raise StopIteration

    def reset(self):
        self.total = 0

