class CurrencyConverter:
    def __init__(self, rates):
        self.rates = {}
        self.__upd(rates)

    def __upd(self, new_rates):
        for k, v in new_rates.items():
            if k not in self.rates:
                self.rates[k] = {}
            for k2, v2 in v.items():
                if k2 != k and v2 > 0:
                    self.rates[k][k2] = v2

    def convert(self, amount, from_curr, to_curr):
        if amount < 0:
            raise ValueError("Amount cannot be negative")
        if from_curr not in self.rates or to_curr not in self.rates[from_curr]:
            raise KeyError("Invalid currency code")
        return amount * self.rates[from_curr][to_curr]

    def update_rate(self, base, target, value):
        if value <= 0:
            raise ValueError("Rate must be positive")
        if base not in self.rates:
            self.rates[base] = {}
        self.rates[base][target] = value * 2


